window.BIBLE["Hosea"] = {"1":{"chapter":"1","title":"GOMER AND HOSEA'S MARRIAGE","verses":{"1":{"text":"The word of the LORD that came unto Hosea, the son of Beeri, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and in the days of Jeroboam the son of Joash, king of Israel.","ref":"Hosea 1:1","synthesized":"This is the word of the LORD that came to Hosea son of Beeri in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and of Jeroboam son of Jehoash, king of Israel.","sources":{"KJV":{"text":"The word of the LORD that came unto Hosea, the son of Beeri, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and in the days of Jeroboam the son of Joash, king of Israel."},"BSB":{"text":"This is the word of the LORD that came to Hosea son of Beeri in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and of Jeroboam son of Jehoash, king of Israel."}},"definableWords":["word","LORD","son","days","kings","Judah","Son","king","Israel"],"peopleInVerse":[]},"2":{"text":"The beginning of the word of the LORD by Hosea. And the LORD said to Hosea, Go, take unto thee a wife of whoredoms and children of whoredoms: for the land hath committed great whoredom, departing from the LORD.","ref":"Hosea 1:2","synthesized":"When the LORD first spoke through Hosea, He told him, “Go, take a prostitute as your wife and have children of adultery, because this land is flagrantly prostituting itself by departing from the LORD.”","sources":{"KJV":{"text":"The beginning of the word of the LORD by Hosea. And the LORD said to Hosea, Go, take unto thee a wife of whoredoms and children of whoredoms: for the land hath committed great whoredom, departing from the LORD."},"BSB":{"text":"When the LORD first spoke through Hosea, He told him, “Go, take a prostitute as your wife and have children of adultery, because this land is flagrantly prostituting itself by departing from the LORD.”"}},"definableWords":["LORD","wife","land","Lord"],"peopleInVerse":[]},"3":{"text":"So he went and took Gomer the daughter of Diblaim; which conceived, and bare him a son.","ref":"Hosea 1:3","synthesized":"So Hosea went and married Gomer daughter of Diblaim, and she conceived and bore him a son.","sources":{"KJV":{"text":"So he went and took Gomer the daughter of Diblaim; which conceived, and bare him a son."},"BSB":{"text":"So Hosea went and married Gomer daughter of Diblaim, and she conceived and bore him a son."}},"definableWords":["daughter","son"],"peopleInVerse":[]},"4":{"text":"And the LORD said unto him, Call his name Jezreel; for yet a little while, and I will avenge the blood of Jezreel upon the house of Jehu, and will cause to cease the kingdom of the house of Israel.","ref":"Hosea 1:4","synthesized":"Then the LORD said to Hosea, “Name him Jezreel, for soon I will bring the bloodshed of Jezreel upon the house of Jehu, and I will put an end to the kingdom of Israel.","sources":{"KJV":{"text":"And the LORD said unto him, Call his name Jezreel; for yet a little while, and I will avenge the blood of Jezreel upon the house of Jehu, and will cause to cease the kingdom of the house of Israel."},"BSB":{"text":"Then the LORD said to Hosea, “Name him Jezreel, for soon I will bring the bloodshed of Jezreel upon the house of Jehu, and I will put an end to the kingdom of Israel."}},"definableWords":["LORD","name","house","kingdom","Israel"],"peopleInVerse":[]},"5":{"text":"And it shall come to pass at that day, that I will break the bow of Israel in the valley of Jezreel.","ref":"Hosea 1:5","synthesized":"And on that day I will break the bow of Israel in the Valley of Jezreel.”","sources":{"KJV":{"text":"And it shall come to pass at that day, that I will break the bow of Israel in the valley of Jezreel."},"BSB":{"text":"And on that day I will break the bow of Israel in the Valley of Jezreel.”"}},"definableWords":["day","Israel"],"peopleInVerse":[]},"6":{"text":"And she conceived again, and bare a daughter. And God said unto him, Call her name Loruhamah: for I will no more have mercy upon the house of Israel; but I will utterly take them away.","ref":"Hosea 1:6","synthesized":"Gomer again conceived and gave birth to a daughter, and the LORD said to Hosea, “Name her Lo-ruhamah, for I will no longer have compassion on the house of Israel, that I should ever forgive them.","sources":{"KJV":{"text":"And she conceived again, and bare a daughter. And God said unto him, Call her name Loruhamah: for I will no more have mercy upon the house of Israel; but I will utterly take them away."},"BSB":{"text":"Gomer again conceived and gave birth to a daughter, and the LORD said to Hosea, “Name her Lo-ruhamah, for I will no longer have compassion on the house of Israel, that I should ever forgive them."}},"definableWords":["daughter","LORD","name","house","Israel","forgive"],"peopleInVerse":[]},"7":{"text":"But I will have mercy upon the house of Judah, and will save them by the LORD their God, and will not save them by bow, nor by sword, nor by battle, by horses, nor by horsemen.","ref":"Hosea 1:7","synthesized":"Yet I will have compassion on the house of Judah, and I will save them—not by bow or sword or war, not by horses and cavalry, but by the LORD their God.”","sources":{"KJV":{"text":"But I will have mercy upon the house of Judah, and will save them by the LORD their God, and will not save them by bow, nor by sword, nor by battle, by horses, nor by horsemen."},"BSB":{"text":"Yet I will have compassion on the house of Judah, and I will save them—not by bow or sword or war, not by horses and cavalry, but by the LORD their God.”"}},"definableWords":["house","Judah","or","LORD","God"],"peopleInVerse":[]},"8":{"text":"Now when she had weaned Loruhamah, she conceived, and bare a son.","ref":"Hosea 1:8","synthesized":"After she had weaned Lo-ruhamah, Gomer conceived and gave birth to a son.","sources":{"KJV":{"text":"Now when she had weaned Loruhamah, she conceived, and bare a son."},"BSB":{"text":"After she had weaned Lo-ruhamah, Gomer conceived and gave birth to a son."}},"definableWords":["son"],"peopleInVerse":[]},"9":{"text":"Then said God, Call his name Loammi: for ye are not my people, and I will not be your God.","ref":"Hosea 1:9","synthesized":"And the LORD said, “Name him Lo-ammi, for you are not My people, and I am not your God.","sources":{"KJV":{"text":"Then said God, Call his name Loammi: for ye are not my people, and I will not be your God."},"BSB":{"text":"And the LORD said, “Name him Lo-ammi, for you are not My people, and I am not your God."}},"definableWords":["LORD","name","people","God"],"peopleInVerse":[]},"10":{"text":"Yet the number of the children of Israel shall be as the sand of the sea, which cannot be measured nor numbered; and it shall come to pass, that in the place where it was said unto them, Ye are not my people, there it shall be said unto them, Ye are the sons of the living God.","ref":"Hosea 1:10","synthesized":"Yet the number of the Israelites will be like the sand of the sea, which cannot be measured or counted. And it will happen that in the very place where it was said to them, ‘You are not My people,’ they will be called ‘sons of the living God.’","sources":{"KJV":{"text":"Yet the number of the children of Israel shall be as the sand of the sea, which cannot be measured nor numbered; and it shall come to pass, that in the place where it was said unto them, Ye are not my people, there it shall be said unto them, Ye are the sons of the living God."},"BSB":{"text":"Yet the number of the Israelites will be like the sand of the sea, which cannot be measured or counted. And it will happen that in the very place where it was said to them, ‘You are not My people,’ they will be called ‘sons of the living God.’"}},"definableWords":["Israelites","sea","or","people","sons","living","God"],"peopleInVerse":[]},"11":{"text":"Then shall the children of Judah and the children of Israel be gathered together, and appoint themselves one head, and they shall come up out of the land: for great shall be the day of Jezreel.","ref":"Hosea 1:11","synthesized":"Then the people of Judah and of Israel will be gathered together, and they will appoint for themselves one leader, and will go up out of the land. For great will be the day of Jezreel.","sources":{"KJV":{"text":"Then shall the children of Judah and the children of Israel be gathered together, and appoint themselves one head, and they shall come up out of the land: for great shall be the day of Jezreel."},"BSB":{"text":"Then the people of Judah and of Israel will be gathered together, and they will appoint for themselves one leader, and will go up out of the land. For great will be the day of Jezreel."}},"definableWords":["people","Judah","Israel","one","land","great","day"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"I WILL ALLURE HER INTO THE WILDERNESS","verses":{"1":{"text":"Say ye unto your brethren, Ammi; and to your sisters, Ruhamah.","ref":"Hosea 2:1","synthesized":"“Say of your brothers, ‘My people,’ and of your sisters, ‘My loved one.’","sources":{"KJV":{"text":"Say ye unto your brethren, Ammi; and to your sisters, Ruhamah."},"BSB":{"text":"“Say of your brothers, ‘My people,’ and of your sisters, ‘My loved one.’"}},"definableWords":["people","one"],"peopleInVerse":[]},"2":{"text":"Plead with your mother, plead: for she is not my wife, neither am I her husband: let her therefore put away her whoredoms out of her sight, and her adulteries from between her breasts;","ref":"Hosea 2:2","synthesized":"Rebuke your mother, rebuke her, for she is not My wife, and I am not her husband. Let her remove the adultery from her face and the unfaithfulness from between her breasts.","sources":{"KJV":{"text":"Plead with your mother, plead: for she is not my wife, neither am I her husband: let her therefore put away her whoredoms out of her sight, and her adulteries from between her breasts;"},"BSB":{"text":"Rebuke your mother, rebuke her, for she is not My wife, and I am not her husband. Let her remove the adultery from her face and the unfaithfulness from between her breasts."}},"definableWords":["mother","wife","husband"],"peopleInVerse":[]},"3":{"text":"Lest I strip her naked, and set her as in the day that she was born, and make her as a wilderness, and set her like a dry land, and slay her with thirst.","ref":"Hosea 2:3","synthesized":"Otherwise, I will strip her naked and expose her like the day of her birth. I will make her like a desert and turn her into a parched land, and I will let her die of thirst.","sources":{"KJV":{"text":"Lest I strip her naked, and set her as in the day that she was born, and make her as a wilderness, and set her like a dry land, and slay her with thirst."},"BSB":{"text":"Otherwise, I will strip her naked and expose her like the day of her birth. I will make her like a desert and turn her into a parched land, and I will let her die of thirst."}},"definableWords":["naked","day","make","land","die"],"peopleInVerse":[]},"4":{"text":"And I will not have mercy upon her children; for they be the children of whoredoms.","ref":"Hosea 2:4","synthesized":"I will have no compassion on her children, because they are the children of adultery.","sources":{"KJV":{"text":"And I will not have mercy upon her children; for they be the children of whoredoms."},"BSB":{"text":"I will have no compassion on her children, because they are the children of adultery."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For their mother hath played the harlot: she that conceived them hath done shamefully: for she said, I will go after my lovers, that give me my bread and my water, my wool and my flax, mine oil and my drink.","ref":"Hosea 2:5","synthesized":"For their mother has played the harlot and has conceived them in disgrace. For she thought, ‘I will go after my lovers, who give me bread and water, wool and linen, oil and drink.’","sources":{"KJV":{"text":"For their mother hath played the harlot: she that conceived them hath done shamefully: for she said, I will go after my lovers, that give me my bread and my water, my wool and my flax, mine oil and my drink."},"BSB":{"text":"For their mother has played the harlot and has conceived them in disgrace. For she thought, ‘I will go after my lovers, who give me bread and water, wool and linen, oil and drink.’"}},"definableWords":["mother","water"],"peopleInVerse":[]},"6":{"text":"Therefore, behold, I will hedge up thy way with thorns, and make a wall, that she shall not find her paths.","ref":"Hosea 2:6","synthesized":"Therefore, behold, I will hedge up her path with thorns; I will enclose her with a wall, so she cannot find her way.","sources":{"KJV":{"text":"Therefore, behold, I will hedge up thy way with thorns, and make a wall, that she shall not find her paths."},"BSB":{"text":"Therefore, behold, I will hedge up her path with thorns; I will enclose her with a wall, so she cannot find her way."}},"definableWords":["way"],"peopleInVerse":[]},"7":{"text":"And she shall follow after her lovers, but she shall not overtake them; and she shall seek them, but shall not find them: then shall she say, I will go and return to my first husband; for then was it better with me than now.","ref":"Hosea 2:7","synthesized":"She will pursue her lovers but not catch them; she will seek them but not find them. Then she will say, ‘I will return to my first husband, for then I was better off than now.’","sources":{"KJV":{"text":"And she shall follow after her lovers, but she shall not overtake them; and she shall seek them, but shall not find them: then shall she say, I will go and return to my first husband; for then was it better with me than now."},"BSB":{"text":"She will pursue her lovers but not catch them; she will seek them but not find them. Then she will say, ‘I will return to my first husband, for then I was better off than now.’"}},"definableWords":["seek","husband"],"peopleInVerse":[]},"8":{"text":"For she did not know that I gave her corn, and wine, and oil, and multiplied her silver and gold, which they prepared for Baal.","ref":"Hosea 2:8","synthesized":"For she does not acknowledge that it was I who gave her grain, new wine, and oil, who lavished on her silver and gold— which they crafted for Baal.","sources":{"KJV":{"text":"For she did not know that I gave her corn, and wine, and oil, and multiplied her silver and gold, which they prepared for Baal."},"BSB":{"text":"For she does not acknowledge that it was I who gave her grain, new wine, and oil, who lavished on her silver and gold— which they crafted for Baal."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Therefore will I return, and take away my corn in the time thereof, and my wine in the season thereof, and will recover my wool and my flax given to cover her nakedness.","ref":"Hosea 2:9","synthesized":"Therefore I will take back My grain in its time and My new wine in its season; I will take away My wool and linen, which were given to cover her nakedness.","sources":{"KJV":{"text":"Therefore will I return, and take away my corn in the time thereof, and my wine in the season thereof, and will recover my wool and my flax given to cover her nakedness."},"BSB":{"text":"Therefore I will take back My grain in its time and My new wine in its season; I will take away My wool and linen, which were given to cover her nakedness."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And now will I discover her lewdness in the sight of her lovers, and none shall deliver her out of mine hand.","ref":"Hosea 2:10","synthesized":"And then I will expose her lewdness in the sight of her lovers, and no one will deliver her out of My hands.","sources":{"KJV":{"text":"And now will I discover her lewdness in the sight of her lovers, and none shall deliver her out of mine hand."},"BSB":{"text":"And then I will expose her lewdness in the sight of her lovers, and no one will deliver her out of My hands."}},"definableWords":["one","deliver"],"peopleInVerse":[]},"11":{"text":"I will also cause all her mirth to cease, her feast days, her new moons, and her sabbaths, and all her solemn feasts.","ref":"Hosea 2:11","synthesized":"I will put an end to all her exultation: her feasts, New Moons, and Sabbaths— all her appointed feasts.","sources":{"KJV":{"text":"I will also cause all her mirth to cease, her feast days, her new moons, and her sabbaths, and all her solemn feasts."},"BSB":{"text":"I will put an end to all her exultation: her feasts, New Moons, and Sabbaths— all her appointed feasts."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And I will destroy her vines and her fig trees, whereof she hath said, These are my rewards that my lovers have given me: and I will make them a forest, and the beasts of the field shall eat them.","ref":"Hosea 2:12","synthesized":"I will destroy her vines and fig trees, which she thinks are the wages paid by her lovers. So I will make them into a thicket, and the beasts of the field will devour them.","sources":{"KJV":{"text":"And I will destroy her vines and her fig trees, whereof she hath said, These are my rewards that my lovers have given me: and I will make them a forest, and the beasts of the field shall eat them."},"BSB":{"text":"I will destroy her vines and fig trees, which she thinks are the wages paid by her lovers. So I will make them into a thicket, and the beasts of the field will devour them."}},"definableWords":["trees","make","field"],"peopleInVerse":[]},"13":{"text":"And I will visit upon her the days of Baalim, wherein she burned incense to them, and she decked herself with her earrings and her jewels, and she went after her lovers, and forgat me, saith the LORD.","ref":"Hosea 2:13","synthesized":"I will punish her for the days of the Baals when she burned incense to them, when she decked herself with rings and jewelry, and went after her lovers.   But Me she forgot,” declares the LORD.","sources":{"KJV":{"text":"And I will visit upon her the days of Baalim, wherein she burned incense to them, and she decked herself with her earrings and her jewels, and she went after her lovers, and forgat me, saith the LORD."},"BSB":{"text":"I will punish her for the days of the Baals when she burned incense to them, when she decked herself with rings and jewelry, and went after her lovers.   But Me she forgot,” declares the LORD."}},"definableWords":["days","incense","LORD"],"peopleInVerse":[]},"14":{"text":"Therefore, behold, I will allure her, and bring her into the wilderness, and speak comfortably unto her.","ref":"Hosea 2:14","synthesized":"“Therefore, behold, I will allure her and lead her to the wilderness, and speak to her tenderly.","sources":{"KJV":{"text":"Therefore, behold, I will allure her, and bring her into the wilderness, and speak comfortably unto her."},"BSB":{"text":"“Therefore, behold, I will allure her and lead her to the wilderness, and speak to her tenderly."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And I will give her her vineyards from thence, and the valley of Achor for a door of hope: and she shall sing there, as in the days of her youth, and as in the day when she came up out of the land of Egypt.","ref":"Hosea 2:15","synthesized":"There I will give back her vineyards and make the Valley of Achor into a gateway of hope. There she will respond as she did in the days of her youth, as in the day she came up out of Egypt.","sources":{"KJV":{"text":"And I will give her her vineyards from thence, and the valley of Achor for a door of hope: and she shall sing there, as in the days of her youth, and as in the day when she came up out of the land of Egypt."},"BSB":{"text":"There I will give back her vineyards and make the Valley of Achor into a gateway of hope. There she will respond as she did in the days of her youth, as in the day she came up out of Egypt."}},"definableWords":["make","hope","days","day","Egypt"],"peopleInVerse":[]},"16":{"text":"And it shall be at that day, saith the LORD, that thou shalt call me Ishi; and shalt call me no more Baali.","ref":"Hosea 2:16","synthesized":"In that day,” declares the LORD, “you will call Me ‘my Husband,’ and no longer call Me ‘my Master.’","sources":{"KJV":{"text":"And it shall be at that day, saith the LORD, that thou shalt call me Ishi; and shalt call me no more Baali."},"BSB":{"text":"In that day,” declares the LORD, “you will call Me ‘my Husband,’ and no longer call Me ‘my Master.’"}},"definableWords":["day","LORD","husband"],"peopleInVerse":[]},"17":{"text":"For I will take away the names of Baalim out of her mouth, and they shall no more be remembered by their name.","ref":"Hosea 2:17","synthesized":"For I will remove from her lips the names of the Baals; no longer will their names be invoked.","sources":{"KJV":{"text":"For I will take away the names of Baalim out of her mouth, and they shall no more be remembered by their name."},"BSB":{"text":"For I will remove from her lips the names of the Baals; no longer will their names be invoked."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"And in that day will I make a covenant for them with the beasts of the field, and with the fowls of heaven, and with the creeping things of the ground: and I will break the bow and the sword and the battle out of the earth, and will make them to lie down safely.","ref":"Hosea 2:18","synthesized":"On that day I will make a covenant for them with the beasts of the field and the birds of the air and the creatures that crawl on the ground. And I will abolish bow and sword and weapons of war in the land, and will make them lie down in safety.","sources":{"KJV":{"text":"And in that day will I make a covenant for them with the beasts of the field, and with the fowls of heaven, and with the creeping things of the ground: and I will break the bow and the sword and the battle out of the earth, and will make them to lie down safely."},"BSB":{"text":"On that day I will make a covenant for them with the beasts of the field and the birds of the air and the creatures that crawl on the ground. And I will abolish bow and sword and weapons of war in the land, and will make them lie down in safety."}},"definableWords":["day","make","covenant","field","birds","ground","land"],"peopleInVerse":[]},"19":{"text":"And I will betroth thee unto me for ever; yea, I will betroth thee unto me in righteousness, and in judgment, and in lovingkindness, and in mercies.","ref":"Hosea 2:19","synthesized":"So I will betroth you to Me forever; I will betroth you in righteousness and justice, in loving devotion and compassion.","sources":{"KJV":{"text":"And I will betroth thee unto me for ever; yea, I will betroth thee unto me in righteousness, and in judgment, and in lovingkindness, and in mercies."},"BSB":{"text":"So I will betroth you to Me forever; I will betroth you in righteousness and justice, in loving devotion and compassion."}},"definableWords":["righteousness","justice"],"peopleInVerse":[]},"20":{"text":"I will even betroth thee unto me in faithfulness: and thou shalt know the LORD.","ref":"Hosea 2:20","synthesized":"And I will betroth you in faithfulness, and you will know the LORD.”","sources":{"KJV":{"text":"I will even betroth thee unto me in faithfulness: and thou shalt know the LORD."},"BSB":{"text":"And I will betroth you in faithfulness, and you will know the LORD.”"}},"definableWords":["LORD"],"peopleInVerse":[]},"21":{"text":"And it shall come to pass in that day, I will hear, saith the LORD, I will hear the heavens, and they shall hear the earth;","ref":"Hosea 2:21","synthesized":"“On that day I will respond—” declares the LORD— “I will respond to the heavens, and they will respond to the earth.","sources":{"KJV":{"text":"And it shall come to pass in that day, I will hear, saith the LORD, I will hear the heavens, and they shall hear the earth;"},"BSB":{"text":"“On that day I will respond—” declares the LORD— “I will respond to the heavens, and they will respond to the earth."}},"definableWords":["day","LORD","heavens","earth"],"peopleInVerse":[]},"22":{"text":"And the earth shall hear the corn, and the wine, and the oil; and they shall hear Jezreel.","ref":"Hosea 2:22","synthesized":"And the earth will respond to the grain, to the new wine and oil, and they will respond to Jezreel.","sources":{"KJV":{"text":"And the earth shall hear the corn, and the wine, and the oil; and they shall hear Jezreel."},"BSB":{"text":"And the earth will respond to the grain, to the new wine and oil, and they will respond to Jezreel."}},"definableWords":["earth"],"peopleInVerse":[]},"23":{"text":"And I will sow her unto me in the earth; and I will have mercy upon her that had not obtained mercy; and I will say to them which were not my people, Thou art my people; and they shall say, Thou art my God.","ref":"Hosea 2:23","synthesized":"And I will sow her as My own in the land, and I will have compassion on ‘No Compassion.’ I will say to those called ‘Not My People,’ ‘You are My people,’ and they will say, ‘You are my God.’”","sources":{"KJV":{"text":"And I will sow her unto me in the earth; and I will have mercy upon her that had not obtained mercy; and I will say to them which were not my people, Thou art my people; and they shall say, Thou art my God."},"BSB":{"text":"And I will sow her as My own in the land, and I will have compassion on ‘No Compassion.’ I will say to those called ‘Not My People,’ ‘You are My people,’ and they will say, ‘You are my God.’”"}},"definableWords":["land","people","God"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"HOSEA REDEEMS GOMER","verses":{"1":{"text":"Then said the LORD unto me, Go yet, love a woman beloved of her friend, yet an adulteress, according to the love of the LORD toward the children of Israel, who look to other gods, and love flagons of wine.","ref":"Hosea 3:1","synthesized":"Then the LORD said to me, “Go show love to your wife again, though she is loved by another and is an adulteress. Love her as the LORD loves the Israelites, though they turn to other gods and offer raisin cakes to idols.”","sources":{"KJV":{"text":"Then said the LORD unto me, Go yet, love a woman beloved of her friend, yet an adulteress, according to the love of the LORD toward the children of Israel, who look to other gods, and love flagons of wine."},"BSB":{"text":"Then the LORD said to me, “Go show love to your wife again, though she is loved by another and is an adulteress. Love her as the LORD loves the Israelites, though they turn to other gods and offer raisin cakes to idols.”"}},"definableWords":["LORD","love","wife","Lord","Israelites"],"peopleInVerse":[]},"2":{"text":"So I bought her to me for fifteen pieces of silver, and for an homer of barley, and an half homer of barley:","ref":"Hosea 3:2","synthesized":"So I bought her for fifteen shekels of silver and a homer and a lethech of barley.","sources":{"KJV":{"text":"So I bought her to me for fifteen pieces of silver, and for an homer of barley, and an half homer of barley:"},"BSB":{"text":"So I bought her for fifteen shekels of silver and a homer and a lethech of barley."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"And I said unto her, Thou shalt abide for me many days; thou shalt not play the harlot, and thou shalt not be for another man: so will I also be for thee.","ref":"Hosea 3:3","synthesized":"Then I said to her, “You must live with me for many days; you must not be promiscuous or belong to another, and I will do the same for you.”","sources":{"KJV":{"text":"And I said unto her, Thou shalt abide for me many days; thou shalt not play the harlot, and thou shalt not be for another man: so will I also be for thee."},"BSB":{"text":"Then I said to her, “You must live with me for many days; you must not be promiscuous or belong to another, and I will do the same for you.”"}},"definableWords":["live","days","or"],"peopleInVerse":[]},"4":{"text":"For the children of Israel shall abide many days without a king, and without a prince, and without a sacrifice, and without an image, and without an ephod, and without teraphim:","ref":"Hosea 3:4","synthesized":"For the Israelites must live many days without king or prince, without sacrifice or sacred pillar, and without ephod or idol.","sources":{"KJV":{"text":"For the children of Israel shall abide many days without a king, and without a prince, and without a sacrifice, and without an image, and without an ephod, and without teraphim:"},"BSB":{"text":"For the Israelites must live many days without king or prince, without sacrifice or sacred pillar, and without ephod or idol."}},"definableWords":["Israelites","live","days","king","or","prince","sacrifice"],"peopleInVerse":[]},"5":{"text":"Afterward shall the children of Israel return, and seek the LORD their God, and David their king; and shall fear the LORD and his goodness in the latter days.","ref":"Hosea 3:5","synthesized":"Afterward, the people of Israel will return and seek the LORD their God and David their king. They will come trembling to the LORD and to His goodness in the last days.","sources":{"KJV":{"text":"Afterward shall the children of Israel return, and seek the LORD their God, and David their king; and shall fear the LORD and his goodness in the latter days."},"BSB":{"text":"Afterward, the people of Israel will return and seek the LORD their God and David their king. They will come trembling to the LORD and to His goodness in the last days."}},"definableWords":["people","Israel","seek","LORD","God","king","Lord","days"],"peopleInVerse":["David"]}}},"4":{"chapter":"4","title":"MY PEOPLE PERISH FOR LACK OF KNOWLEDGE","verses":{"1":{"text":"Hear the word of the LORD, ye children of Israel: for the LORD hath a controversy with the inhabitants of the land, because there is no truth, nor mercy, nor knowledge of God in the land.","ref":"Hosea 4:1","synthesized":"Hear the word of the LORD, O children of Israel, for the LORD has a case against the people of the land:   “There is no truth, no loving devotion, and no knowledge of God in the land!","sources":{"KJV":{"text":"Hear the word of the LORD, ye children of Israel: for the LORD hath a controversy with the inhabitants of the land, because there is no truth, nor mercy, nor knowledge of God in the land."},"BSB":{"text":"Hear the word of the LORD, O children of Israel, for the LORD has a case against the people of the land:   “There is no truth, no loving devotion, and no knowledge of God in the land!"}},"definableWords":["hear","word","LORD","Israel","Lord","people","land","truth","knowledge","God"],"peopleInVerse":[]},"2":{"text":"By swearing, and lying, and killing, and stealing, and committing adultery, they break out, and blood toucheth blood.","ref":"Hosea 4:2","synthesized":"Cursing and lying, murder and stealing, and adultery are rampant; one act of bloodshed follows another.","sources":{"KJV":{"text":"By swearing, and lying, and killing, and stealing, and committing adultery, they break out, and blood toucheth blood."},"BSB":{"text":"Cursing and lying, murder and stealing, and adultery are rampant; one act of bloodshed follows another."}},"definableWords":["one"],"peopleInVerse":[]},"3":{"text":"Therefore shall the land mourn, and every one that dwelleth therein shall languish, with the beasts of the field, and with the fowls of heaven; yea, the fishes of the sea also shall be taken away.","ref":"Hosea 4:3","synthesized":"Therefore the land mourns, and all who dwell in it will waste away with the beasts of the field and the birds of the air; even the fish of the sea disappear.","sources":{"KJV":{"text":"Therefore shall the land mourn, and every one that dwelleth therein shall languish, with the beasts of the field, and with the fowls of heaven; yea, the fishes of the sea also shall be taken away."},"BSB":{"text":"Therefore the land mourns, and all who dwell in it will waste away with the beasts of the field and the birds of the air; even the fish of the sea disappear."}},"definableWords":["land","field","birds","fish","sea"],"peopleInVerse":[]},"4":{"text":"Yet let no man strive, nor reprove another: for thy people are as they that strive with the priest.","ref":"Hosea 4:4","synthesized":"But let no man contend; let no man offer reproof; for your people are like those who contend with a priest.","sources":{"KJV":{"text":"Yet let no man strive, nor reprove another: for thy people are as they that strive with the priest."},"BSB":{"text":"But let no man contend; let no man offer reproof; for your people are like those who contend with a priest."}},"definableWords":["man","people","priest"],"peopleInVerse":[]},"5":{"text":"Therefore shalt thou fall in the day, and the prophet also shall fall with thee in the night, and I will destroy thy mother.","ref":"Hosea 4:5","synthesized":"You will stumble by day, and the prophet will stumble with you by night; so I will destroy your mother—","sources":{"KJV":{"text":"Therefore shalt thou fall in the day, and the prophet also shall fall with thee in the night, and I will destroy thy mother."},"BSB":{"text":"You will stumble by day, and the prophet will stumble with you by night; so I will destroy your mother—"}},"definableWords":["day","prophet","night","mother"],"peopleInVerse":[]},"6":{"text":"My people are destroyed for lack of knowledge: because thou hast rejected knowledge, I will also reject thee, that thou shalt be no priest to me: seeing thou hast forgotten the law of thy God, I will also forget thy children.","ref":"Hosea 4:6","synthesized":"My people are destroyed for lack of knowledge. Because you have rejected knowledge, I will also reject you as My priests. Since you have forgotten the law of your God, I will also forget your children.","sources":{"KJV":{"text":"My people are destroyed for lack of knowledge: because thou hast rejected knowledge, I will also reject thee, that thou shalt be no priest to me: seeing thou hast forgotten the law of thy God, I will also forget thy children."},"BSB":{"text":"My people are destroyed for lack of knowledge. Because you have rejected knowledge, I will also reject you as My priests. Since you have forgotten the law of your God, I will also forget your children."}},"definableWords":["people","knowledge","law","God"],"peopleInVerse":[]},"7":{"text":"As they were increased, so they sinned against me: therefore will I change their glory into shame.","ref":"Hosea 4:7","synthesized":"The more they multiplied, the more they sinned against Me; they exchanged their Glory for a thing of disgrace.","sources":{"KJV":{"text":"As they were increased, so they sinned against me: therefore will I change their glory into shame."},"BSB":{"text":"The more they multiplied, the more they sinned against Me; they exchanged their Glory for a thing of disgrace."}},"definableWords":["glory"],"peopleInVerse":[]},"8":{"text":"They eat up the sin of my people, and they set their heart on their iniquity.","ref":"Hosea 4:8","synthesized":"They feed on the sins of My people and set their hearts on iniquity.","sources":{"KJV":{"text":"They eat up the sin of my people, and they set their heart on their iniquity."},"BSB":{"text":"They feed on the sins of My people and set their hearts on iniquity."}},"definableWords":["people","iniquity"],"peopleInVerse":[]},"9":{"text":"And there shall be, like people, like priest: and I will punish them for their ways, and reward them their doings.","ref":"Hosea 4:9","synthesized":"And it shall be like people, like priest. I will punish both of them for their ways and repay them for their deeds.","sources":{"KJV":{"text":"And there shall be, like people, like priest: and I will punish them for their ways, and reward them their doings."},"BSB":{"text":"And it shall be like people, like priest. I will punish both of them for their ways and repay them for their deeds."}},"definableWords":["people","priest"],"peopleInVerse":[]},"10":{"text":"For they shall eat, and not have enough: they shall commit whoredom, and shall not increase: because they have left off to take heed to the LORD.","ref":"Hosea 4:10","synthesized":"They will eat but not be satisfied; they will be promiscuous but not multiply. For they have stopped obeying the LORD.","sources":{"KJV":{"text":"For they shall eat, and not have enough: they shall commit whoredom, and shall not increase: because they have left off to take heed to the LORD."},"BSB":{"text":"They will eat but not be satisfied; they will be promiscuous but not multiply. For they have stopped obeying the LORD."}},"definableWords":["multiply","LORD"],"peopleInVerse":[]},"11":{"text":"Whoredom and wine and new wine take away the heart.","ref":"Hosea 4:11","synthesized":"Promiscuity, wine, and new wine take away understanding.","sources":{"KJV":{"text":"Whoredom and wine and new wine take away the heart."},"BSB":{"text":"Promiscuity, wine, and new wine take away understanding."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"My people ask counsel at their stocks, and their staff declareth unto them: for the spirit of whoredoms hath caused them to err, and they have gone a whoring from under their God.","ref":"Hosea 4:12","synthesized":"My people consult their wooden idols, and their divining rods inform them. For a spirit of prostitution leads them astray and they have played the harlot against their God.","sources":{"KJV":{"text":"My people ask counsel at their stocks, and their staff declareth unto them: for the spirit of whoredoms hath caused them to err, and they have gone a whoring from under their God."},"BSB":{"text":"My people consult their wooden idols, and their divining rods inform them. For a spirit of prostitution leads them astray and they have played the harlot against their God."}},"definableWords":["people","spirit","God"],"peopleInVerse":[]},"13":{"text":"They sacrifice upon the tops of the mountains, and burn incense upon the hills, under oaks and poplars and elms, because the shadow thereof is good: therefore your daughters shall commit whoredom, and your spouses shall commit adultery.","ref":"Hosea 4:13","synthesized":"They sacrifice on the mountaintops and burn offerings on the hills, under oak, poplar, and terebinth, because their shade is pleasant. And so your daughters turn to prostitution and your daughters-in-law to adultery.","sources":{"KJV":{"text":"They sacrifice upon the tops of the mountains, and burn incense upon the hills, under oaks and poplars and elms, because the shadow thereof is good: therefore your daughters shall commit whoredom, and your spouses shall commit adultery."},"BSB":{"text":"They sacrifice on the mountaintops and burn offerings on the hills, under oak, poplar, and terebinth, because their shade is pleasant. And so your daughters turn to prostitution and your daughters-in-law to adultery."}},"definableWords":["sacrifice","daughters","law"],"peopleInVerse":[]},"14":{"text":"I will not punish your daughters when they commit whoredom, nor your spouses when they commit adultery: for themselves are separated with whores, and they sacrifice with harlots: therefore the people that doth not understand shall fall.","ref":"Hosea 4:14","synthesized":"I will not punish your daughters when they prostitute themselves, nor your daughters-in-law when they commit adultery. For the men themselves go off with prostitutes and offer sacrifices with shrine prostitutes. So a people without understanding will come to ruin.","sources":{"KJV":{"text":"I will not punish your daughters when they commit whoredom, nor your spouses when they commit adultery: for themselves are separated with whores, and they sacrifice with harlots: therefore the people that doth not understand shall fall."},"BSB":{"text":"I will not punish your daughters when they prostitute themselves, nor your daughters-in-law when they commit adultery. For the men themselves go off with prostitutes and offer sacrifices with shrine prostitutes. So a people without understanding will come to ruin."}},"definableWords":["daughters","law","men","people"],"peopleInVerse":[]},"15":{"text":"Though thou, Israel, play the harlot, yet let not Judah offend; and come not ye unto Gilgal, neither go ye up to Bethaven, nor swear, The LORD liveth.","ref":"Hosea 4:15","synthesized":"Though you prostitute yourself, O Israel, may Judah avoid such guilt! Do not journey to Gilgal, do not go up to Beth-aven, and do not swear on oath, ‘As surely as the LORD lives!’","sources":{"KJV":{"text":"Though thou, Israel, play the harlot, yet let not Judah offend; and come not ye unto Gilgal, neither go ye up to Bethaven, nor swear, The LORD liveth."},"BSB":{"text":"Though you prostitute yourself, O Israel, may Judah avoid such guilt! Do not journey to Gilgal, do not go up to Beth-aven, and do not swear on oath, ‘As surely as the LORD lives!’"}},"definableWords":["Israel","Judah","LORD"],"peopleInVerse":[]},"16":{"text":"For Israel slideth back as a backsliding heifer: now the LORD will feed them as a lamb in a large place.","ref":"Hosea 4:16","synthesized":"For Israel is as obstinate as a stubborn heifer. Can the LORD now shepherd them like lambs in an open meadow?","sources":{"KJV":{"text":"For Israel slideth back as a backsliding heifer: now the LORD will feed them as a lamb in a large place."},"BSB":{"text":"For Israel is as obstinate as a stubborn heifer. Can the LORD now shepherd them like lambs in an open meadow?"}},"definableWords":["Israel","LORD","shepherd"],"peopleInVerse":[]},"17":{"text":"Ephraim is joined to idols: let him alone.","ref":"Hosea 4:17","synthesized":"Ephraim is joined to idols; leave him alone!","sources":{"KJV":{"text":"Ephraim is joined to idols: let him alone."},"BSB":{"text":"Ephraim is joined to idols; leave him alone!"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Their drink is sour: they have committed whoredom continually: her rulers with shame do love, Give ye.","ref":"Hosea 4:18","synthesized":"When their liquor is gone, they turn to prostitution; their rulers dearly love disgrace.","sources":{"KJV":{"text":"Their drink is sour: they have committed whoredom continually: her rulers with shame do love, Give ye."},"BSB":{"text":"When their liquor is gone, they turn to prostitution; their rulers dearly love disgrace."}},"definableWords":["love"],"peopleInVerse":[]},"19":{"text":"The wind hath bound her up in her wings, and they shall be ashamed because of their sacrifices.","ref":"Hosea 4:19","synthesized":"The whirlwind has wrapped them in its wings, and their sacrifices will bring them shame.","sources":{"KJV":{"text":"The wind hath bound her up in her wings, and they shall be ashamed because of their sacrifices."},"BSB":{"text":"The whirlwind has wrapped them in its wings, and their sacrifices will bring them shame."}},"definableWords":[],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"EPHRAIM AND JUDAH JUDGED","verses":{"1":{"text":"Hear ye this, O priests; and hearken, ye house of Israel; and give ye ear, O house of the king; for judgment is toward you, because ye have been a snare on Mizpah, and a net spread upon Tabor.","ref":"Hosea 5:1","synthesized":"“Hear this, O priests! Take heed, O house of Israel! Give ear, O royal house! For this judgment is against you because you have been a snare at Mizpah, a net spread out on Tabor.","sources":{"KJV":{"text":"Hear ye this, O priests; and hearken, ye house of Israel; and give ye ear, O house of the king; for judgment is toward you, because ye have been a snare on Mizpah, and a net spread upon Tabor."},"BSB":{"text":"“Hear this, O priests! Take heed, O house of Israel! Give ear, O royal house! For this judgment is against you because you have been a snare at Mizpah, a net spread out on Tabor."}},"definableWords":["hear","house","Israel","judgment"],"peopleInVerse":[]},"2":{"text":"And the revolters are profound to make slaughter, though I have been a rebuker of them all.","ref":"Hosea 5:2","synthesized":"The rebels are deep in slaughter; but I will chastise them all.","sources":{"KJV":{"text":"And the revolters are profound to make slaughter, though I have been a rebuker of them all."},"BSB":{"text":"The rebels are deep in slaughter; but I will chastise them all."}},"definableWords":["deep"],"peopleInVerse":[]},"3":{"text":"I know Ephraim, and Israel is not hid from me: for now, O Ephraim, thou committest whoredom, and Israel is defiled.","ref":"Hosea 5:3","synthesized":"I know all about Ephraim, and Israel is not hidden from Me. For now, O Ephraim, you have turned to prostitution; Israel is defiled.","sources":{"KJV":{"text":"I know Ephraim, and Israel is not hid from me: for now, O Ephraim, thou committest whoredom, and Israel is defiled."},"BSB":{"text":"I know all about Ephraim, and Israel is not hidden from Me. For now, O Ephraim, you have turned to prostitution; Israel is defiled."}},"definableWords":["Israel"],"peopleInVerse":[]},"4":{"text":"They will not frame their doings to turn unto their God: for the spirit of whoredoms is in the midst of them, and they have not known the LORD.","ref":"Hosea 5:4","synthesized":"Their deeds do not permit them to return to their God, for a spirit of prostitution is within them, and they do not know the LORD.","sources":{"KJV":{"text":"They will not frame their doings to turn unto their God: for the spirit of whoredoms is in the midst of them, and they have not known the LORD."},"BSB":{"text":"Their deeds do not permit them to return to their God, for a spirit of prostitution is within them, and they do not know the LORD."}},"definableWords":["God","spirit","LORD"],"peopleInVerse":[]},"5":{"text":"And the pride of Israel doth testify to his face: therefore shall Israel and Ephraim fall in their iniquity; Judah also shall fall with them.","ref":"Hosea 5:5","synthesized":"Israel’s arrogance testifies against them; Israel and Ephraim stumble in their iniquity; even Judah stumbles with them.","sources":{"KJV":{"text":"And the pride of Israel doth testify to his face: therefore shall Israel and Ephraim fall in their iniquity; Judah also shall fall with them."},"BSB":{"text":"Israel’s arrogance testifies against them; Israel and Ephraim stumble in their iniquity; even Judah stumbles with them."}},"definableWords":["Israel","iniquity","Judah"],"peopleInVerse":[]},"6":{"text":"They shall go with their flocks and with their herds to seek the LORD; but they shall not find him; he hath withdrawn himself from them.","ref":"Hosea 5:6","synthesized":"They go with their flocks and herds to seek the LORD, but they do not find Him; He has withdrawn Himself from them.","sources":{"KJV":{"text":"They shall go with their flocks and with their herds to seek the LORD; but they shall not find him; he hath withdrawn himself from them."},"BSB":{"text":"They go with their flocks and herds to seek the LORD, but they do not find Him; He has withdrawn Himself from them."}},"definableWords":["seek","LORD"],"peopleInVerse":[]},"7":{"text":"They have dealt treacherously against the LORD: for they have begotten strange children: now shall a month devour them with their portions.","ref":"Hosea 5:7","synthesized":"They have been unfaithful to the LORD; for they have borne illegitimate children. Now the New Moon will devour them along with their land.","sources":{"KJV":{"text":"They have dealt treacherously against the LORD: for they have begotten strange children: now shall a month devour them with their portions."},"BSB":{"text":"They have been unfaithful to the LORD; for they have borne illegitimate children. Now the New Moon will devour them along with their land."}},"definableWords":["LORD","land"],"peopleInVerse":[]},"8":{"text":"Blow ye the cornet in Gibeah, and the trumpet in Ramah: cry aloud at Bethaven, after thee, O Benjamin.","ref":"Hosea 5:8","synthesized":"Blow the ram’s horn in Gibeah, the trumpet in Ramah; raise the battle cry in Beth-aven: Lead on, O Benjamin!","sources":{"KJV":{"text":"Blow ye the cornet in Gibeah, and the trumpet in Ramah: cry aloud at Bethaven, after thee, O Benjamin."},"BSB":{"text":"Blow the ram’s horn in Gibeah, the trumpet in Ramah; raise the battle cry in Beth-aven: Lead on, O Benjamin!"}},"definableWords":["Benjamin"],"peopleInVerse":[]},"9":{"text":"Ephraim shall be desolate in the day of rebuke: among the tribes of Israel have I made known that which shall surely be.","ref":"Hosea 5:9","synthesized":"Ephraim will be laid waste on the day of rebuke. Among the tribes of Israel I proclaim what is certain.","sources":{"KJV":{"text":"Ephraim shall be desolate in the day of rebuke: among the tribes of Israel have I made known that which shall surely be."},"BSB":{"text":"Ephraim will be laid waste on the day of rebuke. Among the tribes of Israel I proclaim what is certain."}},"definableWords":["day","Israel"],"peopleInVerse":[]},"10":{"text":"The princes of Judah were like them that remove the bound: therefore I will pour out my wrath upon them like water.","ref":"Hosea 5:10","synthesized":"The princes of Judah are like those who move boundary stones; I will pour out My fury upon them like water.","sources":{"KJV":{"text":"The princes of Judah were like them that remove the bound: therefore I will pour out my wrath upon them like water."},"BSB":{"text":"The princes of Judah are like those who move boundary stones; I will pour out My fury upon them like water."}},"definableWords":["Judah","water"],"peopleInVerse":[]},"11":{"text":"Ephraim is oppressed and broken in judgment, because he willingly walked after the commandment.","ref":"Hosea 5:11","synthesized":"Ephraim is oppressed, crushed in judgment, for he is determined to follow worthless idols.","sources":{"KJV":{"text":"Ephraim is oppressed and broken in judgment, because he willingly walked after the commandment."},"BSB":{"text":"Ephraim is oppressed, crushed in judgment, for he is determined to follow worthless idols."}},"definableWords":["judgment"],"peopleInVerse":[]},"12":{"text":"Therefore will I be unto Ephraim as a moth, and to the house of Judah as rottenness.","ref":"Hosea 5:12","synthesized":"So I am like a moth to Ephraim, and like decay to the house of Judah.","sources":{"KJV":{"text":"Therefore will I be unto Ephraim as a moth, and to the house of Judah as rottenness."},"BSB":{"text":"So I am like a moth to Ephraim, and like decay to the house of Judah."}},"definableWords":["house","Judah"],"peopleInVerse":[]},"13":{"text":"When Ephraim saw his sickness, and Judah saw his wound, then went Ephraim to the Assyrian, and sent to king Jareb: yet could he not heal you, nor cure you of your wound.","ref":"Hosea 5:13","synthesized":"When Ephraim saw his sickness and Judah his wound, then Ephraim turned to Assyria and sent to the great king. But he cannot cure you or heal your wound.","sources":{"KJV":{"text":"When Ephraim saw his sickness, and Judah saw his wound, then went Ephraim to the Assyrian, and sent to king Jareb: yet could he not heal you, nor cure you of your wound."},"BSB":{"text":"When Ephraim saw his sickness and Judah his wound, then Ephraim turned to Assyria and sent to the great king. But he cannot cure you or heal your wound."}},"definableWords":["saw","Judah","great","king","or","heal"],"peopleInVerse":[]},"14":{"text":"For I will be unto Ephraim as a lion, and as a young lion to the house of Judah: I, even I, will tear and go away; I will take away, and none shall rescue him.","ref":"Hosea 5:14","synthesized":"For I am like a lion to Ephraim and like a young lion to the house of Judah. I, even I, will tear them to pieces and then go away. I will carry them off where no one can rescue them.","sources":{"KJV":{"text":"For I will be unto Ephraim as a lion, and as a young lion to the house of Judah: I, even I, will tear and go away; I will take away, and none shall rescue him."},"BSB":{"text":"For I am like a lion to Ephraim and like a young lion to the house of Judah. I, even I, will tear them to pieces and then go away. I will carry them off where no one can rescue them."}},"definableWords":["lion","house","Judah","one"],"peopleInVerse":[]},"15":{"text":"I will go and return to my place, till they acknowledge their offence, and seek my face: in their affliction they will seek me early.","ref":"Hosea 5:15","synthesized":"Then I will return to My place until they admit their guilt and seek My face; in their affliction they will earnestly seek Me.”","sources":{"KJV":{"text":"I will go and return to my place, till they acknowledge their offence, and seek my face: in their affliction they will seek me early."},"BSB":{"text":"Then I will return to My place until they admit their guilt and seek My face; in their affliction they will earnestly seek Me.”"}},"definableWords":["seek"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"AFTER TWO DAYS HE WILL REVIVE US","verses":{"1":{"text":"Come, and let us return unto the LORD: for he hath torn, and he will heal us; he hath smitten, and he will bind us up.","ref":"Hosea 6:1","synthesized":"Come, let us return to the LORD.   For He has torn us to pieces, but He will heal us; He has wounded us, but He will bind up our wounds.","sources":{"KJV":{"text":"Come, and let us return unto the LORD: for he hath torn, and he will heal us; he hath smitten, and he will bind us up."},"BSB":{"text":"Come, let us return to the LORD.   For He has torn us to pieces, but He will heal us; He has wounded us, but He will bind up our wounds."}},"definableWords":["LORD","heal"],"peopleInVerse":[]},"2":{"text":"After two days will he revive us: in the third day he will raise us up, and we shall live in his sight.","ref":"Hosea 6:2","synthesized":"After two days He will revive us; on the third day He will raise us up, that we may live in His presence.","sources":{"KJV":{"text":"After two days will he revive us: in the third day he will raise us up, and we shall live in his sight."},"BSB":{"text":"After two days He will revive us; on the third day He will raise us up, that we may live in His presence."}},"definableWords":["days","day","live"],"peopleInVerse":[]},"3":{"text":"Then shall we know, if we follow on to know the LORD: his going forth is prepared as the morning; and he shall come unto us as the rain, as the latter and former rain unto the earth.","ref":"Hosea 6:3","synthesized":"So let us know— let us press on to know the LORD. As surely as the sun rises, He will appear; He will come to us like the rain, like the spring showers that water the earth.","sources":{"KJV":{"text":"Then shall we know, if we follow on to know the LORD: his going forth is prepared as the morning; and he shall come unto us as the rain, as the latter and former rain unto the earth."},"BSB":{"text":"So let us know— let us press on to know the LORD. As surely as the sun rises, He will appear; He will come to us like the rain, like the spring showers that water the earth."}},"definableWords":["LORD","water","earth"],"peopleInVerse":[]},"4":{"text":"O Ephraim, what shall I do unto thee? O Judah, what shall I do unto thee? for your goodness is as a morning cloud, and as the early dew it goeth away.","ref":"Hosea 6:4","synthesized":"What shall I do with you, O Ephraim? What shall I do with you, O Judah? For your loyalty is like a morning mist, like the early dew that vanishes.","sources":{"KJV":{"text":"O Ephraim, what shall I do unto thee? O Judah, what shall I do unto thee? for your goodness is as a morning cloud, and as the early dew it goeth away."},"BSB":{"text":"What shall I do with you, O Ephraim? What shall I do with you, O Judah? For your loyalty is like a morning mist, like the early dew that vanishes."}},"definableWords":["Judah"],"peopleInVerse":[]},"5":{"text":"Therefore have I hewed them by the prophets; I have slain them by the words of my mouth: and thy judgments are as the light that goeth forth.","ref":"Hosea 6:5","synthesized":"Therefore I have hewn them by the prophets; I have slain them by the words of My mouth, and My judgments go forth like lightning.","sources":{"KJV":{"text":"Therefore have I hewed them by the prophets; I have slain them by the words of my mouth: and thy judgments are as the light that goeth forth."},"BSB":{"text":"Therefore I have hewn them by the prophets; I have slain them by the words of My mouth, and My judgments go forth like lightning."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"For I desired mercy, and not sacrifice; and the knowledge of God more than burnt offerings.","ref":"Hosea 6:6","synthesized":"For I desire mercy, not sacrifice, and the knowledge of God rather than burnt offerings.","sources":{"KJV":{"text":"For I desired mercy, and not sacrifice; and the knowledge of God more than burnt offerings."},"BSB":{"text":"For I desire mercy, not sacrifice, and the knowledge of God rather than burnt offerings."}},"definableWords":["mercy","sacrifice","knowledge","God"],"peopleInVerse":[]},"7":{"text":"But they like men have transgressed the covenant: there have they dealt treacherously against me.","ref":"Hosea 6:7","synthesized":"But they, like Adam, have transgressed the covenant; there they were unfaithful to Me.","sources":{"KJV":{"text":"But they like men have transgressed the covenant: there have they dealt treacherously against me."},"BSB":{"text":"But they, like Adam, have transgressed the covenant; there they were unfaithful to Me."}},"definableWords":["Adam","covenant"],"peopleInVerse":["Adam"]},"8":{"text":"Gilead is a city of them that work iniquity, and is polluted with blood.","ref":"Hosea 6:8","synthesized":"Gilead is a city of evildoers, tracked with footprints of blood.","sources":{"KJV":{"text":"Gilead is a city of them that work iniquity, and is polluted with blood."},"BSB":{"text":"Gilead is a city of evildoers, tracked with footprints of blood."}},"definableWords":["blood"],"peopleInVerse":[]},"9":{"text":"And as troops of robbers wait for a man, so the company of priests murder in the way by consent: for they commit lewdness.","ref":"Hosea 6:9","synthesized":"Like raiders who lie in ambush, so does a band of priests; they murder on the way to Shechem; surely they have committed atrocities.","sources":{"KJV":{"text":"And as troops of robbers wait for a man, so the company of priests murder in the way by consent: for they commit lewdness."},"BSB":{"text":"Like raiders who lie in ambush, so does a band of priests; they murder on the way to Shechem; surely they have committed atrocities."}},"definableWords":["way"],"peopleInVerse":[]},"10":{"text":"I have seen an horrible thing in the house of Israel: there is the whoredom of Ephraim, Israel is defiled.","ref":"Hosea 6:10","synthesized":"In the house of Israel I have seen a horrible thing: Ephraim practices prostitution there, and Israel is defiled.","sources":{"KJV":{"text":"I have seen an horrible thing in the house of Israel: there is the whoredom of Ephraim, Israel is defiled."},"BSB":{"text":"In the house of Israel I have seen a horrible thing: Ephraim practices prostitution there, and Israel is defiled."}},"definableWords":["house","Israel"],"peopleInVerse":[]},"11":{"text":"Also, O Judah, he hath set an harvest for thee, when I returned the captivity of my people.","ref":"Hosea 6:11","synthesized":"Also for you, O Judah, a harvest is appointed, when I restore My people from captivity.","sources":{"KJV":{"text":"Also, O Judah, he hath set an harvest for thee, when I returned the captivity of my people."},"BSB":{"text":"Also for you, O Judah, a harvest is appointed, when I restore My people from captivity."}},"definableWords":["Judah","people"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"EPHRAIM IS A CAKE NOT TURNED","verses":{"1":{"text":"When I would have healed Israel, then the iniquity of Ephraim was discovered, and the wickedness of Samaria: for they commit falsehood; and the thief cometh in, and the troop of robbers spoileth without.","ref":"Hosea 7:1","synthesized":"When I heal Israel, the iniquity of Ephraim will be exposed, as well as the crimes of Samaria. For they practice deceit and thieves break in; bandits raid in the streets.","sources":{"KJV":{"text":"When I would have healed Israel, then the iniquity of Ephraim was discovered, and the wickedness of Samaria: for they commit falsehood; and the thief cometh in, and the troop of robbers spoileth without."},"BSB":{"text":"When I heal Israel, the iniquity of Ephraim will be exposed, as well as the crimes of Samaria. For they practice deceit and thieves break in; bandits raid in the streets."}},"definableWords":["heal","Israel","iniquity","Samaria"],"peopleInVerse":[]},"2":{"text":"And they consider not in their hearts that I remember all their wickedness: now their own doings have beset them about; they are before my face.","ref":"Hosea 7:2","synthesized":"But they fail to consider in their hearts that I remember all their evil. Now their deeds are all around them; they are before My face.","sources":{"KJV":{"text":"And they consider not in their hearts that I remember all their wickedness: now their own doings have beset them about; they are before my face."},"BSB":{"text":"But they fail to consider in their hearts that I remember all their evil. Now their deeds are all around them; they are before My face."}},"definableWords":["remember","evil"],"peopleInVerse":[]},"3":{"text":"They make the king glad with their wickedness, and the princes with their lies.","ref":"Hosea 7:3","synthesized":"They delight the king with their evil, and the princes with their lies.","sources":{"KJV":{"text":"They make the king glad with their wickedness, and the princes with their lies."},"BSB":{"text":"They delight the king with their evil, and the princes with their lies."}},"definableWords":["king","evil"],"peopleInVerse":[]},"4":{"text":"They are all adulterers, as an oven heated by the baker, who ceaseth from raising after he hath kneaded the dough, until it be leavened.","ref":"Hosea 7:4","synthesized":"They are all adulterers, like an oven heated by a baker who needs not stoke the fire from the kneading to the rising of the dough.","sources":{"KJV":{"text":"They are all adulterers, as an oven heated by the baker, who ceaseth from raising after he hath kneaded the dough, until it be leavened."},"BSB":{"text":"They are all adulterers, like an oven heated by a baker who needs not stoke the fire from the kneading to the rising of the dough."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"In the day of our king the princes have made him sick with bottles of wine; he stretched out his hand with scorners.","ref":"Hosea 7:5","synthesized":"The princes are inflamed with wine on the day of our king; so he joins hands with those who mock him.","sources":{"KJV":{"text":"In the day of our king the princes have made him sick with bottles of wine; he stretched out his hand with scorners."},"BSB":{"text":"The princes are inflamed with wine on the day of our king; so he joins hands with those who mock him."}},"definableWords":["day","king"],"peopleInVerse":[]},"6":{"text":"For they have made ready their heart like an oven, whiles they lie in wait: their baker sleepeth all the night; in the morning it burneth as a flaming fire.","ref":"Hosea 7:6","synthesized":"For they prepare their heart like an oven while they lie in wait; all night their anger smolders; in the morning it blazes like a flaming fire.","sources":{"KJV":{"text":"For they have made ready their heart like an oven, whiles they lie in wait: their baker sleepeth all the night; in the morning it burneth as a flaming fire."},"BSB":{"text":"For they prepare their heart like an oven while they lie in wait; all night their anger smolders; in the morning it blazes like a flaming fire."}},"definableWords":["heart","wait","night","anger"],"peopleInVerse":[]},"7":{"text":"They are all hot as an oven, and have devoured their judges; all their kings are fallen: there is none among them that calleth unto me.","ref":"Hosea 7:7","synthesized":"All of them are hot as an oven, and they devour their rulers. All their kings fall; not one of them calls upon Me.","sources":{"KJV":{"text":"They are all hot as an oven, and have devoured their judges; all their kings are fallen: there is none among them that calleth unto me."},"BSB":{"text":"All of them are hot as an oven, and they devour their rulers. All their kings fall; not one of them calls upon Me."}},"definableWords":["kings","one"],"peopleInVerse":[]},"8":{"text":"Ephraim, he hath mixed himself among the people; Ephraim is a cake not turned.","ref":"Hosea 7:8","synthesized":"Ephraim mixes with the nations; Ephraim is an unturned cake.","sources":{"KJV":{"text":"Ephraim, he hath mixed himself among the people; Ephraim is a cake not turned."},"BSB":{"text":"Ephraim mixes with the nations; Ephraim is an unturned cake."}},"definableWords":["nations"],"peopleInVerse":[]},"9":{"text":"Strangers have devoured his strength, and he knoweth it not: yea, gray hairs are here and there upon him, yet he knoweth not.","ref":"Hosea 7:9","synthesized":"Foreigners consume his strength, but he does not notice. Even his hair is streaked with gray, but he does not know.","sources":{"KJV":{"text":"Strangers have devoured his strength, and he knoweth it not: yea, gray hairs are here and there upon him, yet he knoweth not."},"BSB":{"text":"Foreigners consume his strength, but he does not notice. Even his hair is streaked with gray, but he does not know."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And the pride of Israel testifieth to his face: and they do not return to the LORD their God, nor seek him for all this.","ref":"Hosea 7:10","synthesized":"Israel’s arrogance testifies against them, yet they do not return to the LORD their God; despite all this, they do not seek Him.","sources":{"KJV":{"text":"And the pride of Israel testifieth to his face: and they do not return to the LORD their God, nor seek him for all this."},"BSB":{"text":"Israel’s arrogance testifies against them, yet they do not return to the LORD their God; despite all this, they do not seek Him."}},"definableWords":["Israel","LORD","God","seek"],"peopleInVerse":[]},"11":{"text":"Ephraim also is like a silly dove without heart: they call to Egypt, they go to Assyria.","ref":"Hosea 7:11","synthesized":"So Ephraim has become like a silly, senseless dove— calling out to Egypt, then turning to Assyria.","sources":{"KJV":{"text":"Ephraim also is like a silly dove without heart: they call to Egypt, they go to Assyria."},"BSB":{"text":"So Ephraim has become like a silly, senseless dove— calling out to Egypt, then turning to Assyria."}},"definableWords":["Egypt"],"peopleInVerse":[]},"12":{"text":"When they shall go, I will spread my net upon them; I will bring them down as the fowls of the heaven; I will chastise them, as their congregation hath heard.","ref":"Hosea 7:12","synthesized":"As they go, I will spread My net over them; I will bring them down like birds of the air. I will chastise them when I hear them flocking together.","sources":{"KJV":{"text":"When they shall go, I will spread my net upon them; I will bring them down as the fowls of the heaven; I will chastise them, as their congregation hath heard."},"BSB":{"text":"As they go, I will spread My net over them; I will bring them down like birds of the air. I will chastise them when I hear them flocking together."}},"definableWords":["birds","hear"],"peopleInVerse":[]},"13":{"text":"Woe unto them! for they have fled from me: destruction unto them! because they have transgressed against me: though I have redeemed them, yet they have spoken lies against me.","ref":"Hosea 7:13","synthesized":"Woe to them, for they have strayed from Me! Destruction to them, for they have rebelled against Me! Though I would redeem them, they speak lies against Me.","sources":{"KJV":{"text":"Woe unto them! for they have fled from me: destruction unto them! because they have transgressed against me: though I have redeemed them, yet they have spoken lies against me."},"BSB":{"text":"Woe to them, for they have strayed from Me! Destruction to them, for they have rebelled against Me! Though I would redeem them, they speak lies against Me."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"And they have not cried unto me with their heart, when they howled upon their beds: they assemble themselves for corn and wine, and they rebel against me.","ref":"Hosea 7:14","synthesized":"They do not cry out to Me from their hearts when they wail upon their beds. They slash themselves for grain and new wine, but turn away from Me.","sources":{"KJV":{"text":"And they have not cried unto me with their heart, when they howled upon their beds: they assemble themselves for corn and wine, and they rebel against me."},"BSB":{"text":"They do not cry out to Me from their hearts when they wail upon their beds. They slash themselves for grain and new wine, but turn away from Me."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Though I have bound and strengthened their arms, yet do they imagine mischief against me.","ref":"Hosea 7:15","synthesized":"Although I trained and strengthened their arms, they plot evil against Me.","sources":{"KJV":{"text":"Though I have bound and strengthened their arms, yet do they imagine mischief against me."},"BSB":{"text":"Although I trained and strengthened their arms, they plot evil against Me."}},"definableWords":["evil"],"peopleInVerse":[]},"16":{"text":"They return, but not to the most High: they are like a deceitful bow: their princes shall fall by the sword for the rage of their tongue: this shall be their derision in the land of Egypt.","ref":"Hosea 7:16","synthesized":"They turn, but not to the Most High; they are like a faulty bow. Their leaders will fall by the sword for the cursing of their tongue; for this they will be ridiculed in the land of Egypt.","sources":{"KJV":{"text":"They return, but not to the most High: they are like a deceitful bow: their princes shall fall by the sword for the rage of their tongue: this shall be their derision in the land of Egypt."},"BSB":{"text":"They turn, but not to the Most High; they are like a faulty bow. Their leaders will fall by the sword for the cursing of their tongue; for this they will be ridiculed in the land of Egypt."}},"definableWords":["land","Egypt"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"THEY HAVE SOWN THE WIND","verses":{"1":{"text":"Set the trumpet to thy mouth. He shall come as an eagle against the house of the LORD, because they have transgressed my covenant, and trespassed against my law.","ref":"Hosea 8:1","synthesized":"Put the ram’s horn to your lips! An eagle looms over the house of the LORD, because the people have transgressed My covenant and rebelled against My law.","sources":{"KJV":{"text":"Set the trumpet to thy mouth. He shall come as an eagle against the house of the LORD, because they have transgressed my covenant, and trespassed against my law."},"BSB":{"text":"Put the ram’s horn to your lips! An eagle looms over the house of the LORD, because the people have transgressed My covenant and rebelled against My law."}},"definableWords":["house","LORD","people","covenant","law"],"peopleInVerse":[]},"2":{"text":"Israel shall cry unto me, My God, we know thee.","ref":"Hosea 8:2","synthesized":"Israel cries out to Me, “O our God, we know You!”","sources":{"KJV":{"text":"Israel shall cry unto me, My God, we know thee."},"BSB":{"text":"Israel cries out to Me, “O our God, we know You!”"}},"definableWords":["Israel","God"],"peopleInVerse":[]},"3":{"text":"Israel hath cast off the thing that is good: the enemy shall pursue him.","ref":"Hosea 8:3","synthesized":"But Israel has rejected good; an enemy will pursue him.","sources":{"KJV":{"text":"Israel hath cast off the thing that is good: the enemy shall pursue him."},"BSB":{"text":"But Israel has rejected good; an enemy will pursue him."}},"definableWords":["Israel","good"],"peopleInVerse":[]},"4":{"text":"They have set up kings, but not by me: they have made princes, and I knew it not: of their silver and their gold have they made them idols, that they may be cut off.","ref":"Hosea 8:4","synthesized":"They set up kings, but not by Me. They make princes, but without My approval. With their silver and gold they make themselves idols, to their own destruction.","sources":{"KJV":{"text":"They have set up kings, but not by me: they have made princes, and I knew it not: of their silver and their gold have they made them idols, that they may be cut off."},"BSB":{"text":"They set up kings, but not by Me. They make princes, but without My approval. With their silver and gold they make themselves idols, to their own destruction."}},"definableWords":["kings","make"],"peopleInVerse":[]},"5":{"text":"Thy calf, O Samaria, hath cast thee off; mine anger is kindled against them: how long will it be ere they attain to innocency?","ref":"Hosea 8:5","synthesized":"He has rejected your calf, O Samaria. My anger burns against them. How long will they be incapable of innocence?","sources":{"KJV":{"text":"Thy calf, O Samaria, hath cast thee off; mine anger is kindled against them: how long will it be ere they attain to innocency?"},"BSB":{"text":"He has rejected your calf, O Samaria. My anger burns against them. How long will they be incapable of innocence?"}},"definableWords":["Samaria","anger"],"peopleInVerse":[]},"6":{"text":"For from Israel was it also: the workman made it; therefore it is not God: but the calf of Samaria shall be broken in pieces.","ref":"Hosea 8:6","synthesized":"For this thing is from Israel— a craftsman made it, and it is not God. It will be broken to pieces, that calf of Samaria.","sources":{"KJV":{"text":"For from Israel was it also: the workman made it; therefore it is not God: but the calf of Samaria shall be broken in pieces."},"BSB":{"text":"For this thing is from Israel— a craftsman made it, and it is not God. It will be broken to pieces, that calf of Samaria."}},"definableWords":["Israel","made","God","Samaria"],"peopleInVerse":[]},"7":{"text":"For they have sown the wind, and they shall reap the whirlwind: it hath no stalk: the bud shall yield no meal: if so be it yield, the strangers shall swallow it up.","ref":"Hosea 8:7","synthesized":"For they sow the wind, and they shall reap the whirlwind. There is no standing grain; what sprouts fails to yield flour. Even if it should produce, the foreigners would swallow it up.","sources":{"KJV":{"text":"For they have sown the wind, and they shall reap the whirlwind: it hath no stalk: the bud shall yield no meal: if so be it yield, the strangers shall swallow it up."},"BSB":{"text":"For they sow the wind, and they shall reap the whirlwind. There is no standing grain; what sprouts fails to yield flour. Even if it should produce, the foreigners would swallow it up."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Israel is swallowed up: now shall they be among the Gentiles as a vessel wherein is no pleasure.","ref":"Hosea 8:8","synthesized":"Israel is swallowed up! Now they are among the nations like a worthless vessel.","sources":{"KJV":{"text":"Israel is swallowed up: now shall they be among the Gentiles as a vessel wherein is no pleasure."},"BSB":{"text":"Israel is swallowed up! Now they are among the nations like a worthless vessel."}},"definableWords":["Israel","nations"],"peopleInVerse":[]},"9":{"text":"For they are gone up to Assyria, a wild ass alone by himself: Ephraim hath hired lovers.","ref":"Hosea 8:9","synthesized":"For they have gone up to Assyria like a wild donkey on its own. Ephraim has hired lovers.","sources":{"KJV":{"text":"For they are gone up to Assyria, a wild ass alone by himself: Ephraim hath hired lovers."},"BSB":{"text":"For they have gone up to Assyria like a wild donkey on its own. Ephraim has hired lovers."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Yea, though they have hired among the nations, now will I gather them, and they shall sorrow a little for the burden of the king of princes.","ref":"Hosea 8:10","synthesized":"Though they hire allies among the nations, I will now round them up, and they will begin to diminish under the oppression of the king of princes.","sources":{"KJV":{"text":"Yea, though they have hired among the nations, now will I gather them, and they shall sorrow a little for the burden of the king of princes."},"BSB":{"text":"Though they hire allies among the nations, I will now round them up, and they will begin to diminish under the oppression of the king of princes."}},"definableWords":["nations","begin","king"],"peopleInVerse":[]},"11":{"text":"Because Ephraim hath made many altars to sin, altars shall be unto him to sin.","ref":"Hosea 8:11","synthesized":"Though Ephraim multiplied the altars for sin, they became his altars for sinning.","sources":{"KJV":{"text":"Because Ephraim hath made many altars to sin, altars shall be unto him to sin."},"BSB":{"text":"Though Ephraim multiplied the altars for sin, they became his altars for sinning."}},"definableWords":["sin"],"peopleInVerse":[]},"12":{"text":"I have written to him the great things of my law, but they were counted as a strange thing.","ref":"Hosea 8:12","synthesized":"Though I wrote for them the great things of My law, they regarded them as something strange.","sources":{"KJV":{"text":"I have written to him the great things of my law, but they were counted as a strange thing."},"BSB":{"text":"Though I wrote for them the great things of My law, they regarded them as something strange."}},"definableWords":["great","law"],"peopleInVerse":[]},"13":{"text":"They sacrifice flesh for the sacrifices of mine offerings, and eat it; but the LORD accepteth them not; now will he remember their iniquity, and visit their sins: they shall return to Egypt.","ref":"Hosea 8:13","synthesized":"Though they offer sacrifices as gifts to Me, and though they eat the meat, the LORD does not accept them. Now He will remember their iniquity and punish their sins: They will return to Egypt.","sources":{"KJV":{"text":"They sacrifice flesh for the sacrifices of mine offerings, and eat it; but the LORD accepteth them not; now will he remember their iniquity, and visit their sins: they shall return to Egypt."},"BSB":{"text":"Though they offer sacrifices as gifts to Me, and though they eat the meat, the LORD does not accept them. Now He will remember their iniquity and punish their sins: They will return to Egypt."}},"definableWords":["LORD","remember","iniquity","Egypt"],"peopleInVerse":[]},"14":{"text":"For Israel hath forgotten his Maker, and buildeth temples; and Judah hath multiplied fenced cities: but I will send a fire upon his cities, and it shall devour the palaces thereof.","ref":"Hosea 8:14","synthesized":"Israel has forgotten his Maker and built palaces; Judah has multiplied its fortified cities. But I will send fire upon their cities, and it will consume their citadels.","sources":{"KJV":{"text":"For Israel hath forgotten his Maker, and buildeth temples; and Judah hath multiplied fenced cities: but I will send a fire upon his cities, and it shall devour the palaces thereof."},"BSB":{"text":"Israel has forgotten his Maker and built palaces; Judah has multiplied its fortified cities. But I will send fire upon their cities, and it will consume their citadels."}},"definableWords":["Israel","Judah"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"DAYS OF VISITATION ARE COME","verses":{"1":{"text":"Rejoice not, O Israel, for joy, as other people: for thou hast gone a whoring from thy God, thou hast loved a reward upon every cornfloor.","ref":"Hosea 9:1","synthesized":"Do not rejoice, O Israel, with exultation like the nations, for you have played the harlot against your God; you have made love for hire on every threshing floor.","sources":{"KJV":{"text":"Rejoice not, O Israel, for joy, as other people: for thou hast gone a whoring from thy God, thou hast loved a reward upon every cornfloor."},"BSB":{"text":"Do not rejoice, O Israel, with exultation like the nations, for you have played the harlot against your God; you have made love for hire on every threshing floor."}},"definableWords":["Israel","nations","God","made","love"],"peopleInVerse":[]},"2":{"text":"The floor and the winepress shall not feed them, and the new wine shall fail in her.","ref":"Hosea 9:2","synthesized":"The threshing floor and winepress will not feed them, and the new wine will fail them.","sources":{"KJV":{"text":"The floor and the winepress shall not feed them, and the new wine shall fail in her."},"BSB":{"text":"The threshing floor and winepress will not feed them, and the new wine will fail them."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"They shall not dwell in the LORD’s land; but Ephraim shall return to Egypt, and they shall eat unclean things in Assyria.","ref":"Hosea 9:3","synthesized":"They will not remain in the land of the LORD; Ephraim will return to Egypt and eat unclean food in Assyria.","sources":{"KJV":{"text":"They shall not dwell in the LORD’s land; but Ephraim shall return to Egypt, and they shall eat unclean things in Assyria."},"BSB":{"text":"They will not remain in the land of the LORD; Ephraim will return to Egypt and eat unclean food in Assyria."}},"definableWords":["land","LORD","Egypt"],"peopleInVerse":[]},"4":{"text":"They shall not offer wine offerings to the LORD, neither shall they be pleasing unto him: their sacrifices shall be unto them as the bread of mourners; all that eat thereof shall be polluted: for their bread for their soul shall not come into the house of the LORD.","ref":"Hosea 9:4","synthesized":"They will not pour out wine offerings to the LORD, and their sacrifices will not please Him, but will be to them like the bread of mourners; all who eat will be defiled. For their bread will be for themselves; it will not enter the house of the LORD.","sources":{"KJV":{"text":"They shall not offer wine offerings to the LORD, neither shall they be pleasing unto him: their sacrifices shall be unto them as the bread of mourners; all that eat thereof shall be polluted: for their bread for their soul shall not come into the house of the LORD."},"BSB":{"text":"They will not pour out wine offerings to the LORD, and their sacrifices will not please Him, but will be to them like the bread of mourners; all who eat will be defiled. For their bread will be for themselves; it will not enter the house of the LORD."}},"definableWords":["LORD","house","Lord"],"peopleInVerse":[]},"5":{"text":"What will ye do in the solemn day, and in the day of the feast of the LORD?","ref":"Hosea 9:5","synthesized":"What will you do on the appointed day, on the day of the LORD’s feast?","sources":{"KJV":{"text":"What will ye do in the solemn day, and in the day of the feast of the LORD?"},"BSB":{"text":"What will you do on the appointed day, on the day of the LORD’s feast?"}},"definableWords":["day","LORD"],"peopleInVerse":[]},"6":{"text":"For, lo, they are gone because of destruction: Egypt shall gather them up, Memphis shall bury them: the pleasant places for their silver, nettles shall possess them: thorns shall be in their tabernacles.","ref":"Hosea 9:6","synthesized":"For even if they flee destruction, Egypt will gather them and Memphis will bury them. Their precious silver will be taken over by thistles, and thorns will overrun their tents.","sources":{"KJV":{"text":"For, lo, they are gone because of destruction: Egypt shall gather them up, Memphis shall bury them: the pleasant places for their silver, nettles shall possess them: thorns shall be in their tabernacles."},"BSB":{"text":"For even if they flee destruction, Egypt will gather them and Memphis will bury them. Their precious silver will be taken over by thistles, and thorns will overrun their tents."}},"definableWords":["Egypt"],"peopleInVerse":[]},"7":{"text":"The days of visitation are come, the days of recompence are come; Israel shall know it: the prophet is a fool, the spiritual man is mad, for the multitude of thine iniquity, and the great hatred.","ref":"Hosea 9:7","synthesized":"The days of punishment have come; the days of retribution have arrived— let Israel know it. The prophet is called a fool, and the inspired man insane, because of the greatness of your iniquity and hostility.","sources":{"KJV":{"text":"The days of visitation are come, the days of recompence are come; Israel shall know it: the prophet is a fool, the spiritual man is mad, for the multitude of thine iniquity, and the great hatred."},"BSB":{"text":"The days of punishment have come; the days of retribution have arrived— let Israel know it. The prophet is called a fool, and the inspired man insane, because of the greatness of your iniquity and hostility."}},"definableWords":["days","Israel","prophet","fool","man","iniquity"],"peopleInVerse":[]},"8":{"text":"The watchman of Ephraim was with my God: but the prophet is a snare of a fowler in all his ways, and hatred in the house of his God.","ref":"Hosea 9:8","synthesized":"The prophet is Ephraim’s watchman, along with my God, yet the snare of the fowler lies on all his paths. Hostility is in the house of his God!","sources":{"KJV":{"text":"The watchman of Ephraim was with my God: but the prophet is a snare of a fowler in all his ways, and hatred in the house of his God."},"BSB":{"text":"The prophet is Ephraim’s watchman, along with my God, yet the snare of the fowler lies on all his paths. Hostility is in the house of his God!"}},"definableWords":["prophet","God","house"],"peopleInVerse":[]},"9":{"text":"They have deeply corrupted themselves, as in the days of Gibeah: therefore he will remember their iniquity, he will visit their sins.","ref":"Hosea 9:9","synthesized":"They have deeply corrupted themselves as in the days of Gibeah; He will remember their guilt; He will punish their sins.","sources":{"KJV":{"text":"They have deeply corrupted themselves, as in the days of Gibeah: therefore he will remember their iniquity, he will visit their sins."},"BSB":{"text":"They have deeply corrupted themselves as in the days of Gibeah; He will remember their guilt; He will punish their sins."}},"definableWords":["days","remember"],"peopleInVerse":[]},"10":{"text":"I found Israel like grapes in the wilderness; I saw your fathers as the firstripe in the fig tree at her first time: but they went to Baalpeor, and separated themselves unto that shame; and their abominations were according as they loved.","ref":"Hosea 9:10","synthesized":"I found Israel like grapes in the wilderness. I saw your fathers as the firstfruits of the fig tree in its first season. But they went to Baal-peor, and consecrated themselves to Shame; so they became as detestable as the thing they loved.","sources":{"KJV":{"text":"I found Israel like grapes in the wilderness; I saw your fathers as the firstripe in the fig tree at her first time: but they went to Baalpeor, and separated themselves unto that shame; and their abominations were according as they loved."},"BSB":{"text":"I found Israel like grapes in the wilderness. I saw your fathers as the firstfruits of the fig tree in its first season. But they went to Baal-peor, and consecrated themselves to Shame; so they became as detestable as the thing they loved."}},"definableWords":["Israel","saw","fathers","tree"],"peopleInVerse":[]},"11":{"text":"As for Ephraim, their glory shall fly away like a bird, from the birth, and from the womb, and from the conception.","ref":"Hosea 9:11","synthesized":"Ephraim’s glory will fly away like a bird, with no birth, no pregnancy, and no conception.","sources":{"KJV":{"text":"As for Ephraim, their glory shall fly away like a bird, from the birth, and from the womb, and from the conception."},"BSB":{"text":"Ephraim’s glory will fly away like a bird, with no birth, no pregnancy, and no conception."}},"definableWords":["glory","bird"],"peopleInVerse":[]},"12":{"text":"Though they bring up their children, yet will I bereave them, that there shall not be a man left: yea, woe also to them when I depart from them!","ref":"Hosea 9:12","synthesized":"Even if they raise their children, I will bereave them of each one. Yes, woe be to them when I turn away from them!","sources":{"KJV":{"text":"Though they bring up their children, yet will I bereave them, that there shall not be a man left: yea, woe also to them when I depart from them!"},"BSB":{"text":"Even if they raise their children, I will bereave them of each one. Yes, woe be to them when I turn away from them!"}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Ephraim, as I saw Tyrus, is planted in a pleasant place: but Ephraim shall bring forth his children to the murderer.","ref":"Hosea 9:13","synthesized":"I have seen Ephraim, like Tyre, planted in a meadow. But Ephraim will bring out his children for slaughter.","sources":{"KJV":{"text":"Ephraim, as I saw Tyrus, is planted in a pleasant place: but Ephraim shall bring forth his children to the murderer."},"BSB":{"text":"I have seen Ephraim, like Tyre, planted in a meadow. But Ephraim will bring out his children for slaughter."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Give them, O LORD: what wilt thou give? give them a miscarrying womb and dry breasts.","ref":"Hosea 9:14","synthesized":"Give them, O LORD— what will You give? Give them wombs that miscarry and breasts that dry up!","sources":{"KJV":{"text":"Give them, O LORD: what wilt thou give? give them a miscarrying womb and dry breasts."},"BSB":{"text":"Give them, O LORD— what will You give? Give them wombs that miscarry and breasts that dry up!"}},"definableWords":["LORD"],"peopleInVerse":[]},"15":{"text":"All their wickedness is in Gilgal: for there I hated them: for the wickedness of their doings I will drive them out of mine house, I will love them no more: all their princes are revolters.","ref":"Hosea 9:15","synthesized":"All their evil appears at Gilgal, for there I hated them. I will drive them from My house for the wickedness of their deeds. I will no longer love them; all their leaders are rebellious.","sources":{"KJV":{"text":"All their wickedness is in Gilgal: for there I hated them: for the wickedness of their doings I will drive them out of mine house, I will love them no more: all their princes are revolters."},"BSB":{"text":"All their evil appears at Gilgal, for there I hated them. I will drive them from My house for the wickedness of their deeds. I will no longer love them; all their leaders are rebellious."}},"definableWords":["evil","house","love"],"peopleInVerse":[]},"16":{"text":"Ephraim is smitten, their root is dried up, they shall bear no fruit: yea, though they bring forth, yet will I slay even the beloved fruit of their womb.","ref":"Hosea 9:16","synthesized":"Ephraim is struck down; their root is withered; they cannot bear fruit. Even if they bear children, I will slay the darlings of their wombs.","sources":{"KJV":{"text":"Ephraim is smitten, their root is dried up, they shall bear no fruit: yea, though they bring forth, yet will I slay even the beloved fruit of their womb."},"BSB":{"text":"Ephraim is struck down; their root is withered; they cannot bear fruit. Even if they bear children, I will slay the darlings of their wombs."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"My God will cast them away, because they did not hearken unto him: and they shall be wanderers among the nations.","ref":"Hosea 9:17","synthesized":"My God will reject them because they have not obeyed Him; and they shall be wanderers among the nations.","sources":{"KJV":{"text":"My God will cast them away, because they did not hearken unto him: and they shall be wanderers among the nations."},"BSB":{"text":"My God will reject them because they have not obeyed Him; and they shall be wanderers among the nations."}},"definableWords":["God","nations"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"ISRAEL IS AN EMPTY VINE","verses":{"1":{"text":"Israel is an empty vine, he bringeth forth fruit unto himself: according to the multitude of his fruit he hath increased the altars; according to the goodness of his land they have made goodly images.","ref":"Hosea 10:1","synthesized":"Israel was a luxuriant vine, yielding fruit for himself. The more his fruit increased, the more he increased the altars. The better his land produced, the better he made the sacred pillars.","sources":{"KJV":{"text":"Israel is an empty vine, he bringeth forth fruit unto himself: according to the multitude of his fruit he hath increased the altars; according to the goodness of his land they have made goodly images."},"BSB":{"text":"Israel was a luxuriant vine, yielding fruit for himself. The more his fruit increased, the more he increased the altars. The better his land produced, the better he made the sacred pillars."}},"definableWords":["Israel","land","made"],"peopleInVerse":[]},"2":{"text":"Their heart is divided; now shall they be found faulty: he shall break down their altars, he shall spoil their images.","ref":"Hosea 10:2","synthesized":"Their hearts are devious; now they must bear their guilt. The LORD will break down their altars and demolish their sacred pillars.","sources":{"KJV":{"text":"Their heart is divided; now shall they be found faulty: he shall break down their altars, he shall spoil their images."},"BSB":{"text":"Their hearts are devious; now they must bear their guilt. The LORD will break down their altars and demolish their sacred pillars."}},"definableWords":["LORD"],"peopleInVerse":[]},"3":{"text":"For now they shall say, We have no king, because we feared not the LORD; what then should a king do to us?","ref":"Hosea 10:3","synthesized":"Surely now they will say, “We have no king, for we do not revere the LORD. What can a king do for us?”","sources":{"KJV":{"text":"For now they shall say, We have no king, because we feared not the LORD; what then should a king do to us?"},"BSB":{"text":"Surely now they will say, “We have no king, for we do not revere the LORD. What can a king do for us?”"}},"definableWords":["king","LORD","King"],"peopleInVerse":[]},"4":{"text":"They have spoken words, swearing falsely in making a covenant: thus judgment springeth up as hemlock in the furrows of the field.","ref":"Hosea 10:4","synthesized":"They speak mere words; with false oaths they make covenants. So judgment springs up like poisonous weeds in the furrows of a field.","sources":{"KJV":{"text":"They have spoken words, swearing falsely in making a covenant: thus judgment springeth up as hemlock in the furrows of the field."},"BSB":{"text":"They speak mere words; with false oaths they make covenants. So judgment springs up like poisonous weeds in the furrows of a field."}},"definableWords":["make","judgment","field"],"peopleInVerse":[]},"5":{"text":"The inhabitants of Samaria shall fear because of the calves of Bethaven: for the people thereof shall mourn over it, and the priests thereof that rejoiced on it, for the glory thereof, because it is departed from it.","ref":"Hosea 10:5","synthesized":"The people of Samaria will fear for the calf of Beth-aven. Indeed, its people will mourn with its idolatrous priests— those who rejoiced in its glory— for it has been taken from them into exile.","sources":{"KJV":{"text":"The inhabitants of Samaria shall fear because of the calves of Bethaven: for the people thereof shall mourn over it, and the priests thereof that rejoiced on it, for the glory thereof, because it is departed from it."},"BSB":{"text":"The people of Samaria will fear for the calf of Beth-aven. Indeed, its people will mourn with its idolatrous priests— those who rejoiced in its glory— for it has been taken from them into exile."}},"definableWords":["people","Samaria","fear","glory"],"peopleInVerse":[]},"6":{"text":"It shall be also carried unto Assyria for a present to king Jareb: Ephraim shall receive shame, and Israel shall be ashamed of his own counsel.","ref":"Hosea 10:6","synthesized":"Yes, it will be carried to Assyria as tribute to the great king. Ephraim will be seized with shame; Israel will be ashamed of its wooden idols.","sources":{"KJV":{"text":"It shall be also carried unto Assyria for a present to king Jareb: Ephraim shall receive shame, and Israel shall be ashamed of his own counsel."},"BSB":{"text":"Yes, it will be carried to Assyria as tribute to the great king. Ephraim will be seized with shame; Israel will be ashamed of its wooden idols."}},"definableWords":["great","king","Israel"],"peopleInVerse":[]},"7":{"text":"As for Samaria, her king is cut off as the foam upon the water.","ref":"Hosea 10:7","synthesized":"Samaria will be carried off with her king like a twig on the surface of the water.","sources":{"KJV":{"text":"As for Samaria, her king is cut off as the foam upon the water."},"BSB":{"text":"Samaria will be carried off with her king like a twig on the surface of the water."}},"definableWords":["Samaria","king","water"],"peopleInVerse":[]},"8":{"text":"The high places also of Aven, the sin of Israel, shall be destroyed: the thorn and the thistle shall come up on their altars; and they shall say to the mountains, Cover us; and to the hills, Fall on us.","ref":"Hosea 10:8","synthesized":"The high places of Aven will be destroyed— it is the sin of Israel; thorns and thistles will overgrow their altars. Then they will say to the mountains, “Cover us!” and to the hills, “Fall on us!”","sources":{"KJV":{"text":"The high places also of Aven, the sin of Israel, shall be destroyed: the thorn and the thistle shall come up on their altars; and they shall say to the mountains, Cover us; and to the hills, Fall on us."},"BSB":{"text":"The high places of Aven will be destroyed— it is the sin of Israel; thorns and thistles will overgrow their altars. Then they will say to the mountains, “Cover us!” and to the hills, “Fall on us!”"}},"definableWords":["sin","Israel"],"peopleInVerse":[]},"9":{"text":"O Israel, thou hast sinned from the days of Gibeah: there they stood: the battle in Gibeah against the children of iniquity did not overtake them.","ref":"Hosea 10:9","synthesized":"Since the days of Gibeah you have sinned, O Israel, and there you have remained. Did not the battle in Gibeah overtake the sons of iniquity?","sources":{"KJV":{"text":"O Israel, thou hast sinned from the days of Gibeah: there they stood: the battle in Gibeah against the children of iniquity did not overtake them."},"BSB":{"text":"Since the days of Gibeah you have sinned, O Israel, and there you have remained. Did not the battle in Gibeah overtake the sons of iniquity?"}},"definableWords":["days","Israel","sons","iniquity"],"peopleInVerse":[]},"10":{"text":"It is in my desire that I should chastise them; and the people shall be gathered against them, when they shall bind themselves in their two furrows.","ref":"Hosea 10:10","synthesized":"I will chasten them when I please; nations will be gathered against them to put them in bondage for their double transgression.","sources":{"KJV":{"text":"It is in my desire that I should chastise them; and the people shall be gathered against them, when they shall bind themselves in their two furrows."},"BSB":{"text":"I will chasten them when I please; nations will be gathered against them to put them in bondage for their double transgression."}},"definableWords":["nations","transgression"],"peopleInVerse":[]},"11":{"text":"And Ephraim is as an heifer that is taught, and loveth to tread out the corn; but I passed over upon her fair neck: I will make Ephraim to ride; Judah shall plow, and Jacob shall break his clods.","ref":"Hosea 10:11","synthesized":"Ephraim is a well-trained heifer that loves to thresh; but I will place a yoke on her fair neck. I will harness Ephraim, Judah will plow, and Jacob will break the hard ground.","sources":{"KJV":{"text":"And Ephraim is as an heifer that is taught, and loveth to tread out the corn; but I passed over upon her fair neck: I will make Ephraim to ride; Judah shall plow, and Jacob shall break his clods."},"BSB":{"text":"Ephraim is a well-trained heifer that loves to thresh; but I will place a yoke on her fair neck. I will harness Ephraim, Judah will plow, and Jacob will break the hard ground."}},"definableWords":["Judah","Jacob","ground"],"peopleInVerse":["Jacob"]},"12":{"text":"Sow to yourselves in righteousness, reap in mercy; break up your fallow ground: for it is time to seek the LORD, till he come and rain righteousness upon you.","ref":"Hosea 10:12","synthesized":"Sow for yourselves righteousness and reap the fruit of loving devotion; break up your unplowed ground. For it is time to seek the LORD until He comes and sends righteousness upon you like rain.","sources":{"KJV":{"text":"Sow to yourselves in righteousness, reap in mercy; break up your fallow ground: for it is time to seek the LORD, till he come and rain righteousness upon you."},"BSB":{"text":"Sow for yourselves righteousness and reap the fruit of loving devotion; break up your unplowed ground. For it is time to seek the LORD until He comes and sends righteousness upon you like rain."}},"definableWords":["righteousness","ground","seek","LORD"],"peopleInVerse":[]},"13":{"text":"Ye have plowed wickedness, ye have reaped iniquity; ye have eaten the fruit of lies: because thou didst trust in thy way, in the multitude of thy mighty men.","ref":"Hosea 10:13","synthesized":"You have plowed wickedness and reaped injustice; you have eaten the fruit of lies. Because you have trusted in your own way and in the multitude of your mighty men,","sources":{"KJV":{"text":"Ye have plowed wickedness, ye have reaped iniquity; ye have eaten the fruit of lies: because thou didst trust in thy way, in the multitude of thy mighty men."},"BSB":{"text":"You have plowed wickedness and reaped injustice; you have eaten the fruit of lies. Because you have trusted in your own way and in the multitude of your mighty men,"}},"definableWords":["way","mighty","men"],"peopleInVerse":[]},"14":{"text":"Therefore shall a tumult arise among thy people, and all thy fortresses shall be spoiled, as Shalman spoiled Betharbel in the day of battle: the mother was dashed in pieces upon her children.","ref":"Hosea 10:14","synthesized":"the roar of battle will rise against your people, so that all your fortresses will be demolished as Shalman devastated Beth-arbel in the day of battle, when mothers were dashed to pieces along with their children.","sources":{"KJV":{"text":"Therefore shall a tumult arise among thy people, and all thy fortresses shall be spoiled, as Shalman spoiled Betharbel in the day of battle: the mother was dashed in pieces upon her children."},"BSB":{"text":"the roar of battle will rise against your people, so that all your fortresses will be demolished as Shalman devastated Beth-arbel in the day of battle, when mothers were dashed to pieces along with their children."}},"definableWords":["people","day"],"peopleInVerse":[]},"15":{"text":"So shall Bethel do unto you because of your great wickedness: in a morning shall the king of Israel utterly be cut off.","ref":"Hosea 10:15","synthesized":"Thus it will be done to you, O Bethel, because of your great wickedness. When the day dawns, the king of Israel will be utterly cut off.","sources":{"KJV":{"text":"So shall Bethel do unto you because of your great wickedness: in a morning shall the king of Israel utterly be cut off."},"BSB":{"text":"Thus it will be done to you, O Bethel, because of your great wickedness. When the day dawns, the king of Israel will be utterly cut off."}},"definableWords":["Bethel","great","day","king","Israel"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"WHEN ISRAEL WAS A CHILD","verses":{"1":{"text":"When Israel was a child, then I loved him, and called my son out of Egypt.","ref":"Hosea 11:1","synthesized":"When Israel was a child, I loved him, and out of Egypt I called My son.","sources":{"KJV":{"text":"When Israel was a child, then I loved him, and called my son out of Egypt."},"BSB":{"text":"When Israel was a child, I loved him, and out of Egypt I called My son."}},"definableWords":["Israel","Egypt","son"],"peopleInVerse":[]},"2":{"text":"As they called them, so they went from them: they sacrificed unto Baalim, and burned incense to graven images.","ref":"Hosea 11:2","synthesized":"But the more I called Israel, the farther they departed from Me. They sacrificed to the Baals and burned incense to carved images.","sources":{"KJV":{"text":"As they called them, so they went from them: they sacrificed unto Baalim, and burned incense to graven images."},"BSB":{"text":"But the more I called Israel, the farther they departed from Me. They sacrificed to the Baals and burned incense to carved images."}},"definableWords":["Israel","incense"],"peopleInVerse":[]},"3":{"text":"I taught Ephraim also to go, taking them by their arms; but they knew not that I healed them.","ref":"Hosea 11:3","synthesized":"It was I who taught Ephraim to walk, taking them in My arms, but they never realized that it was I who healed them.","sources":{"KJV":{"text":"I taught Ephraim also to go, taking them by their arms; but they knew not that I healed them."},"BSB":{"text":"It was I who taught Ephraim to walk, taking them in My arms, but they never realized that it was I who healed them."}},"definableWords":["walk"],"peopleInVerse":[]},"4":{"text":"I drew them with cords of a man, with bands of love: and I was to them as they that take off the yoke on their jaws, and I laid meat unto them.","ref":"Hosea 11:4","synthesized":"I led them with cords of kindness, with ropes of love; I lifted the yoke from their necks and bent down to feed them.","sources":{"KJV":{"text":"I drew them with cords of a man, with bands of love: and I was to them as they that take off the yoke on their jaws, and I laid meat unto them."},"BSB":{"text":"I led them with cords of kindness, with ropes of love; I lifted the yoke from their necks and bent down to feed them."}},"definableWords":["kindness","love"],"peopleInVerse":[]},"5":{"text":"He shall not return into the land of Egypt, but the Assyrian shall be his king, because they refused to return.","ref":"Hosea 11:5","synthesized":"Will they not return to the land of Egypt and be ruled by Assyria because they refused to repent?","sources":{"KJV":{"text":"He shall not return into the land of Egypt, but the Assyrian shall be his king, because they refused to return."},"BSB":{"text":"Will they not return to the land of Egypt and be ruled by Assyria because they refused to repent?"}},"definableWords":["land","Egypt"],"peopleInVerse":[]},"6":{"text":"And the sword shall abide on his cities, and shall consume his branches, and devour them, because of their own counsels.","ref":"Hosea 11:6","synthesized":"A sword will flash through their cities; it will destroy the bars of their gates and consume them in their own plans.","sources":{"KJV":{"text":"And the sword shall abide on his cities, and shall consume his branches, and devour them, because of their own counsels."},"BSB":{"text":"A sword will flash through their cities; it will destroy the bars of their gates and consume them in their own plans."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And my people are bent to backsliding from me: though they called them to the most High, none at all would exalt him.","ref":"Hosea 11:7","synthesized":"My people are bent on turning from Me. Though they call to the Most High, He will by no means exalt them.","sources":{"KJV":{"text":"And my people are bent to backsliding from me: though they called them to the most High, none at all would exalt him."},"BSB":{"text":"My people are bent on turning from Me. Though they call to the Most High, He will by no means exalt them."}},"definableWords":["people"],"peopleInVerse":[]},"8":{"text":"How shall I give thee up, Ephraim? how shall I deliver thee, Israel? how shall I make thee as Admah? how shall I set thee as Zeboim? mine heart is turned within me, my repentings are kindled together.","ref":"Hosea 11:8","synthesized":"How could I give you up, O Ephraim? How could I surrender you, O Israel? How could I make you like Admah? How could I treat you like Zeboiim? My heart is turned within Me; My compassion is stirred!","sources":{"KJV":{"text":"How shall I give thee up, Ephraim? how shall I deliver thee, Israel? how shall I make thee as Admah? how shall I set thee as Zeboim? mine heart is turned within me, my repentings are kindled together."},"BSB":{"text":"How could I give you up, O Ephraim? How could I surrender you, O Israel? How could I make you like Admah? How could I treat you like Zeboiim? My heart is turned within Me; My compassion is stirred!"}},"definableWords":["Israel","make","heart"],"peopleInVerse":[]},"9":{"text":"I will not execute the fierceness of mine anger, I will not return to destroy Ephraim: for I am God, and not man; the Holy One in the midst of thee: and I will not enter into the city.","ref":"Hosea 11:9","synthesized":"I will not execute the full fury of My anger; I will not turn back to destroy Ephraim. For I am God and not man— the Holy One among you— and I will not come in wrath.","sources":{"KJV":{"text":"I will not execute the fierceness of mine anger, I will not return to destroy Ephraim: for I am God, and not man; the Holy One in the midst of thee: and I will not enter into the city."},"BSB":{"text":"I will not execute the full fury of My anger; I will not turn back to destroy Ephraim. For I am God and not man— the Holy One among you— and I will not come in wrath."}},"definableWords":["anger","God","man","holy","one","wrath"],"peopleInVerse":[]},"10":{"text":"They shall walk after the LORD: he shall roar like a lion: when he shall roar, then the children shall tremble from the west.","ref":"Hosea 11:10","synthesized":"They will walk after the LORD; He will roar like a lion. When He roars, His children will come trembling from the west.","sources":{"KJV":{"text":"They shall walk after the LORD: he shall roar like a lion: when he shall roar, then the children shall tremble from the west."},"BSB":{"text":"They will walk after the LORD; He will roar like a lion. When He roars, His children will come trembling from the west."}},"definableWords":["walk","LORD","lion"],"peopleInVerse":[]},"11":{"text":"They shall tremble as a bird out of Egypt, and as a dove out of the land of Assyria: and I will place them in their houses, saith the LORD.","ref":"Hosea 11:11","synthesized":"They will come trembling like birds from Egypt and like doves from the land of Assyria. Then I will settle them in their homes, declares the LORD.","sources":{"KJV":{"text":"They shall tremble as a bird out of Egypt, and as a dove out of the land of Assyria: and I will place them in their houses, saith the LORD."},"BSB":{"text":"They will come trembling like birds from Egypt and like doves from the land of Assyria. Then I will settle them in their homes, declares the LORD."}},"definableWords":["birds","Egypt","land","LORD"],"peopleInVerse":[]},"12":{"text":"Ephraim compasseth me about with lies, and the house of Israel with deceit: but Judah yet ruleth with God, and is faithful with the saints.","ref":"Hosea 11:12","synthesized":"Ephraim surrounds Me with lies, the house of Israel with deceit; but Judah still walks with God and is faithful to the Holy One.","sources":{"KJV":{"text":"Ephraim compasseth me about with lies, and the house of Israel with deceit: but Judah yet ruleth with God, and is faithful with the saints."},"BSB":{"text":"Ephraim surrounds Me with lies, the house of Israel with deceit; but Judah still walks with God and is faithful to the Holy One."}},"definableWords":["house","Israel","Judah","God","holy","one"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"EPHRAIM FEEDETH ON WIND","verses":{"1":{"text":"Ephraim feedeth on wind, and followeth after the east wind: he daily increaseth lies and desolation; and they do make a covenant with the Assyrians, and oil is carried into Egypt.","ref":"Hosea 12:1","synthesized":"Ephraim chases the wind and pursues the east wind all day long; he multiplies lies and violence; he makes a covenant with Assyria and sends olive oil to Egypt.","sources":{"KJV":{"text":"Ephraim feedeth on wind, and followeth after the east wind: he daily increaseth lies and desolation; and they do make a covenant with the Assyrians, and oil is carried into Egypt."},"BSB":{"text":"Ephraim chases the wind and pursues the east wind all day long; he multiplies lies and violence; he makes a covenant with Assyria and sends olive oil to Egypt."}},"definableWords":["day","covenant","Egypt"],"peopleInVerse":[]},"2":{"text":"The LORD hath also a controversy with Judah, and will punish Jacob according to his ways; according to his doings will he recompense him.","ref":"Hosea 12:2","synthesized":"The LORD also brings a charge against Judah. He will punish Jacob according to his ways and repay him according to his deeds.","sources":{"KJV":{"text":"The LORD hath also a controversy with Judah, and will punish Jacob according to his ways; according to his doings will he recompense him."},"BSB":{"text":"The LORD also brings a charge against Judah. He will punish Jacob according to his ways and repay him according to his deeds."}},"definableWords":["LORD","charge","Judah","Jacob"],"peopleInVerse":["Jacob"]},"3":{"text":"He took his brother by the heel in the womb, and by his strength he had power with God:","ref":"Hosea 12:3","synthesized":"In the womb he grasped his brother’s heel, and in his vigor he wrestled with God.","sources":{"KJV":{"text":"He took his brother by the heel in the womb, and by his strength he had power with God:"},"BSB":{"text":"In the womb he grasped his brother’s heel, and in his vigor he wrestled with God."}},"definableWords":["brother","God"],"peopleInVerse":[]},"4":{"text":"Yea, he had power over the angel, and prevailed: he wept, and made supplication unto him: he found him in Bethel, and there he spake with us;","ref":"Hosea 12:4","synthesized":"Yes, he struggled with the angel and prevailed; he wept and sought His favor; he found Him at Bethel and spoke with Him there—","sources":{"KJV":{"text":"Yea, he had power over the angel, and prevailed: he wept, and made supplication unto him: he found him in Bethel, and there he spake with us;"},"BSB":{"text":"Yes, he struggled with the angel and prevailed; he wept and sought His favor; he found Him at Bethel and spoke with Him there—"}},"definableWords":["angel","Bethel"],"peopleInVerse":[]},"5":{"text":"Even the LORD God of hosts; the LORD is his memorial.","ref":"Hosea 12:5","synthesized":"the LORD is the God of Hosts— the LORD is His name of renown.","sources":{"KJV":{"text":"Even the LORD God of hosts; the LORD is his memorial."},"BSB":{"text":"the LORD is the God of Hosts— the LORD is His name of renown."}},"definableWords":["LORD","God","Lord","name"],"peopleInVerse":[]},"6":{"text":"Therefore turn thou to thy God: keep mercy and judgment, and wait on thy God continually.","ref":"Hosea 12:6","synthesized":"But you must return to your God, maintaining love and justice, and always waiting on your God.","sources":{"KJV":{"text":"Therefore turn thou to thy God: keep mercy and judgment, and wait on thy God continually."},"BSB":{"text":"But you must return to your God, maintaining love and justice, and always waiting on your God."}},"definableWords":["God","love","justice"],"peopleInVerse":[]},"7":{"text":"He is a merchant, the balances of deceit are in his hand: he loveth to oppress.","ref":"Hosea 12:7","synthesized":"A merchant loves to defraud with dishonest scales in his hands.","sources":{"KJV":{"text":"He is a merchant, the balances of deceit are in his hand: he loveth to oppress."},"BSB":{"text":"A merchant loves to defraud with dishonest scales in his hands."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And Ephraim said, Yet I am become rich, I have found me out substance: in all my labours they shall find none iniquity in me that were sin.","ref":"Hosea 12:8","synthesized":"And Ephraim boasts: “How rich I have become! I have found wealth for myself. In all my labors, they can find in me no iniquity that is sinful.”","sources":{"KJV":{"text":"And Ephraim said, Yet I am become rich, I have found me out substance: in all my labours they shall find none iniquity in me that were sin."},"BSB":{"text":"And Ephraim boasts: “How rich I have become! I have found wealth for myself. In all my labors, they can find in me no iniquity that is sinful.”"}},"definableWords":["iniquity"],"peopleInVerse":[]},"9":{"text":"And I that am the LORD thy God from the land of Egypt will yet make thee to dwell in tabernacles, as in the days of the solemn feast.","ref":"Hosea 12:9","synthesized":"But I am the LORD your God ever since the land of Egypt. I will again make you dwell in tents, as in the days of the appointed feast.","sources":{"KJV":{"text":"And I that am the LORD thy God from the land of Egypt will yet make thee to dwell in tabernacles, as in the days of the solemn feast."},"BSB":{"text":"But I am the LORD your God ever since the land of Egypt. I will again make you dwell in tents, as in the days of the appointed feast."}},"definableWords":["LORD","God","land","Egypt","make","days"],"peopleInVerse":[]},"10":{"text":"I have also spoken by the prophets, and I have multiplied visions, and used similitudes, by the ministry of the prophets.","ref":"Hosea 12:10","synthesized":"I spoke through the prophets and multiplied their visions; I gave parables through the prophets.","sources":{"KJV":{"text":"I have also spoken by the prophets, and I have multiplied visions, and used similitudes, by the ministry of the prophets."},"BSB":{"text":"I spoke through the prophets and multiplied their visions; I gave parables through the prophets."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Is there iniquity in Gilead? surely they are vanity: they sacrifice bullocks in Gilgal; yea, their altars are as heaps in the furrows of the fields.","ref":"Hosea 12:11","synthesized":"Is there iniquity in Gilead? They will surely come to nothing. Do they sacrifice bulls in Gilgal? Indeed, their altars will be heaps of stones in the furrows of the field.","sources":{"KJV":{"text":"Is there iniquity in Gilead? surely they are vanity: they sacrifice bullocks in Gilgal; yea, their altars are as heaps in the furrows of the fields."},"BSB":{"text":"Is there iniquity in Gilead? They will surely come to nothing. Do they sacrifice bulls in Gilgal? Indeed, their altars will be heaps of stones in the furrows of the field."}},"definableWords":["iniquity","sacrifice","field"],"peopleInVerse":[]},"12":{"text":"And Jacob fled into the country of Syria, and Israel served for a wife, and for a wife he kept sheep.","ref":"Hosea 12:12","synthesized":"Jacob fled to the land of Aram and Israel worked for a wife— for a wife he tended sheep.","sources":{"KJV":{"text":"And Jacob fled into the country of Syria, and Israel served for a wife, and for a wife he kept sheep."},"BSB":{"text":"Jacob fled to the land of Aram and Israel worked for a wife— for a wife he tended sheep."}},"definableWords":["Jacob","land","Israel","wife"],"peopleInVerse":["Jacob"]},"13":{"text":"And by a prophet the LORD brought Israel out of Egypt, and by a prophet was he preserved.","ref":"Hosea 12:13","synthesized":"But by a prophet the LORD brought Israel out of Egypt, and by a prophet he was preserved.","sources":{"KJV":{"text":"And by a prophet the LORD brought Israel out of Egypt, and by a prophet was he preserved."},"BSB":{"text":"But by a prophet the LORD brought Israel out of Egypt, and by a prophet he was preserved."}},"definableWords":["prophet","LORD","Israel","Egypt"],"peopleInVerse":[]},"14":{"text":"Ephraim provoked him to anger most bitterly: therefore shall he leave his blood upon him, and his reproach shall his LORD return unto him.","ref":"Hosea 12:14","synthesized":"Ephraim has provoked bitter anger, so his Lord will leave his bloodguilt upon him and repay him for his contempt.","sources":{"KJV":{"text":"Ephraim provoked him to anger most bitterly: therefore shall he leave his blood upon him, and his reproach shall his LORD return unto him."},"BSB":{"text":"Ephraim has provoked bitter anger, so his Lord will leave his bloodguilt upon him and repay him for his contempt."}},"definableWords":["anger","Lord"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"DESTRUCTION IS THINE","verses":{"1":{"text":"When Ephraim spake trembling, he exalted himself in Israel; but when he offended in Baal, he died.","ref":"Hosea 13:1","synthesized":"When Ephraim spoke, there was trembling; he was exalted in Israel. But he incurred guilt through Baal, and he died.","sources":{"KJV":{"text":"When Ephraim spake trembling, he exalted himself in Israel; but when he offended in Baal, he died."},"BSB":{"text":"When Ephraim spoke, there was trembling; he was exalted in Israel. But he incurred guilt through Baal, and he died."}},"definableWords":["Israel"],"peopleInVerse":[]},"2":{"text":"And now they sin more and more, and have made them molten images of their silver, and idols according to their own understanding, all of it the work of the craftsmen: they say of them, Let the men that sacrifice kiss the calves.","ref":"Hosea 13:2","synthesized":"Now they sin more and more and make for themselves cast images, idols skillfully made from their silver, all of them the work of craftsmen. People say of them, “They offer human sacrifice and kiss the calves!”","sources":{"KJV":{"text":"And now they sin more and more, and have made them molten images of their silver, and idols according to their own understanding, all of it the work of the craftsmen: they say of them, Let the men that sacrifice kiss the calves."},"BSB":{"text":"Now they sin more and more and make for themselves cast images, idols skillfully made from their silver, all of them the work of craftsmen. People say of them, “They offer human sacrifice and kiss the calves!”"}},"definableWords":["sin","make","made","work","people","sacrifice"],"peopleInVerse":[]},"3":{"text":"Therefore they shall be as the morning cloud, and as the early dew that passeth away, as the chaff that is driven with the whirlwind out of the floor, and as the smoke out of the chimney.","ref":"Hosea 13:3","synthesized":"Therefore they will be like the morning mist, like the early dew that vanishes, like chaff blown from a threshing floor, like smoke through an open window.","sources":{"KJV":{"text":"Therefore they shall be as the morning cloud, and as the early dew that passeth away, as the chaff that is driven with the whirlwind out of the floor, and as the smoke out of the chimney."},"BSB":{"text":"Therefore they will be like the morning mist, like the early dew that vanishes, like chaff blown from a threshing floor, like smoke through an open window."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Yet I am the LORD thy God from the land of Egypt, and thou shalt know no god but me: for there is no saviour beside me.","ref":"Hosea 13:4","synthesized":"Yet I am the LORD your God ever since the land of Egypt; you know no God but Me, for there is no Savior besides Me.","sources":{"KJV":{"text":"Yet I am the LORD thy God from the land of Egypt, and thou shalt know no god but me: for there is no saviour beside me."},"BSB":{"text":"Yet I am the LORD your God ever since the land of Egypt; you know no God but Me, for there is no Savior besides Me."}},"definableWords":["LORD","God","land","Egypt"],"peopleInVerse":[]},"5":{"text":"I did know thee in the wilderness, in the land of great drought.","ref":"Hosea 13:5","synthesized":"I knew you in the wilderness, in the land of drought.","sources":{"KJV":{"text":"I did know thee in the wilderness, in the land of great drought."},"BSB":{"text":"I knew you in the wilderness, in the land of drought."}},"definableWords":["land"],"peopleInVerse":[]},"6":{"text":"According to their pasture, so were they filled; they were filled, and their heart was exalted; therefore have they forgotten me.","ref":"Hosea 13:6","synthesized":"When they had pasture, they became satisfied; when they were satisfied, their hearts became proud, and as a result they forgot Me.","sources":{"KJV":{"text":"According to their pasture, so were they filled; they were filled, and their heart was exalted; therefore have they forgotten me."},"BSB":{"text":"When they had pasture, they became satisfied; when they were satisfied, their hearts became proud, and as a result they forgot Me."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Therefore I will be unto them as a lion: as a leopard by the way will I observe them:","ref":"Hosea 13:7","synthesized":"So like a lion I will pounce on them; like a leopard I will lurk by the path.","sources":{"KJV":{"text":"Therefore I will be unto them as a lion: as a leopard by the way will I observe them:"},"BSB":{"text":"So like a lion I will pounce on them; like a leopard I will lurk by the path."}},"definableWords":["lion"],"peopleInVerse":[]},"8":{"text":"I will meet them as a bear that is bereaved of her whelps, and will rend the caul of their heart, and there will I devour them like a lion: the wild beast shall tear them.","ref":"Hosea 13:8","synthesized":"Like a bear robbed of her cubs I will attack them, and I will tear open their chests. There I will devour them like a lion, like a wild beast would tear them apart.","sources":{"KJV":{"text":"I will meet them as a bear that is bereaved of her whelps, and will rend the caul of their heart, and there will I devour them like a lion: the wild beast shall tear them."},"BSB":{"text":"Like a bear robbed of her cubs I will attack them, and I will tear open their chests. There I will devour them like a lion, like a wild beast would tear them apart."}},"definableWords":["lion"],"peopleInVerse":[]},"9":{"text":"O Israel, thou hast destroyed thyself; but in me is thine help.","ref":"Hosea 13:9","synthesized":"You are destroyed, O Israel, because you are against Me— against your helper.","sources":{"KJV":{"text":"O Israel, thou hast destroyed thyself; but in me is thine help."},"BSB":{"text":"You are destroyed, O Israel, because you are against Me— against your helper."}},"definableWords":["Israel","helper"],"peopleInVerse":[]},"10":{"text":"I will be thy king: where is any other that may save thee in all thy cities? and thy judges of whom thou saidst, Give me a king and princes?","ref":"Hosea 13:10","synthesized":"Where is your king now to save you in all your cities, and the rulers to whom you said, “Give me a king and princes”?","sources":{"KJV":{"text":"I will be thy king: where is any other that may save thee in all thy cities? and thy judges of whom thou saidst, Give me a king and princes?"},"BSB":{"text":"Where is your king now to save you in all your cities, and the rulers to whom you said, “Give me a king and princes”?"}},"definableWords":["king","King"],"peopleInVerse":[]},"11":{"text":"I gave thee a king in mine anger, and took him away in my wrath.","ref":"Hosea 13:11","synthesized":"So in My anger I gave you a king, and in My wrath I took him away.","sources":{"KJV":{"text":"I gave thee a king in mine anger, and took him away in my wrath."},"BSB":{"text":"So in My anger I gave you a king, and in My wrath I took him away."}},"definableWords":["anger","king","wrath"],"peopleInVerse":[]},"12":{"text":"The iniquity of Ephraim is bound up; his sin is hid.","ref":"Hosea 13:12","synthesized":"The iniquity of Ephraim is bound up; his sin is stored up.","sources":{"KJV":{"text":"The iniquity of Ephraim is bound up; his sin is hid."},"BSB":{"text":"The iniquity of Ephraim is bound up; his sin is stored up."}},"definableWords":["iniquity","sin"],"peopleInVerse":[]},"13":{"text":"The sorrows of a travailing woman shall come upon him: he is an unwise son; for he should not stay long in the place of the breaking forth of children.","ref":"Hosea 13:13","synthesized":"Labor pains come upon him, but he is an unwise son. When the time arrives, he fails to present himself at the opening of the womb.","sources":{"KJV":{"text":"The sorrows of a travailing woman shall come upon him: he is an unwise son; for he should not stay long in the place of the breaking forth of children."},"BSB":{"text":"Labor pains come upon him, but he is an unwise son. When the time arrives, he fails to present himself at the opening of the womb."}},"definableWords":["son"],"peopleInVerse":[]},"14":{"text":"I will ransom them from the power of the grave; I will redeem them from death: O death, I will be thy plagues; O grave, I will be thy destruction: repentance shall be hid from mine eyes.","ref":"Hosea 13:14","synthesized":"I will ransom them from the power of Sheol; I will redeem them from Death. Where, O Death, are your plagues? Where, O Sheol, is your sting?   Compassion is hidden from My eyes.","sources":{"KJV":{"text":"I will ransom them from the power of the grave; I will redeem them from death: O death, I will be thy plagues; O grave, I will be thy destruction: repentance shall be hid from mine eyes."},"BSB":{"text":"I will ransom them from the power of Sheol; I will redeem them from Death. Where, O Death, are your plagues? Where, O Sheol, is your sting?   Compassion is hidden from My eyes."}},"definableWords":["death"],"peopleInVerse":[]},"15":{"text":"Though he be fruitful among his brethren, an east wind shall come, the wind of the LORD shall come up from the wilderness, and his spring shall become dry, and his fountain shall be dried up: he shall spoil the treasure of all pleasant vessels.","ref":"Hosea 13:15","synthesized":"Although he flourishes among his brothers, an east wind will come— a wind from the LORD rising up from the desert. His fountain will fail, and his spring will run dry. The wind will plunder his treasury of every precious article.","sources":{"KJV":{"text":"Though he be fruitful among his brethren, an east wind shall come, the wind of the LORD shall come up from the wilderness, and his spring shall become dry, and his fountain shall be dried up: he shall spoil the treasure of all pleasant vessels."},"BSB":{"text":"Although he flourishes among his brothers, an east wind will come— a wind from the LORD rising up from the desert. His fountain will fail, and his spring will run dry. The wind will plunder his treasury of every precious article."}},"definableWords":["LORD","run"],"peopleInVerse":[]},"16":{"text":"Samaria shall become desolate; for she hath rebelled against her God: they shall fall by the sword: their infants shall be dashed in pieces, and their women with child shall be ripped up.","ref":"Hosea 13:16","synthesized":"Samaria will bear her guilt because she has rebelled against her God. They will fall by the sword; their little ones will be dashed to pieces, and their pregnant women ripped open.","sources":{"KJV":{"text":"Samaria shall become desolate; for she hath rebelled against her God: they shall fall by the sword: their infants shall be dashed in pieces, and their women with child shall be ripped up."},"BSB":{"text":"Samaria will bear her guilt because she has rebelled against her God. They will fall by the sword; their little ones will be dashed to pieces, and their pregnant women ripped open."}},"definableWords":["Samaria","God","women"],"peopleInVerse":[]}}},"14":{"chapter":"14","title":"I WILL HEAL THEIR BACKSLIDING","verses":{"1":{"text":"O Israel, return unto the LORD thy God; for thou hast fallen by thine iniquity.","ref":"Hosea 14:1","synthesized":"Return, O Israel, to the LORD your God, for you have stumbled by your iniquity.","sources":{"KJV":{"text":"O Israel, return unto the LORD thy God; for thou hast fallen by thine iniquity."},"BSB":{"text":"Return, O Israel, to the LORD your God, for you have stumbled by your iniquity."}},"definableWords":["Israel","LORD","God","iniquity"],"peopleInVerse":[]},"2":{"text":"Take with you words, and turn to the LORD: say unto him, Take away all iniquity, and receive us graciously: so will we render the calves of our lips.","ref":"Hosea 14:2","synthesized":"Bring your confessions and return to the LORD. Say to Him: “Take away all our iniquity and receive us graciously, that we may present the fruit of our lips.","sources":{"KJV":{"text":"Take with you words, and turn to the LORD: say unto him, Take away all iniquity, and receive us graciously: so will we render the calves of our lips."},"BSB":{"text":"Bring your confessions and return to the LORD. Say to Him: “Take away all our iniquity and receive us graciously, that we may present the fruit of our lips."}},"definableWords":["LORD","iniquity"],"peopleInVerse":[]},"3":{"text":"Asshur shall not save us; we will not ride upon horses: neither will we say any more to the work of our hands, Ye are our gods: for in thee the fatherless findeth mercy.","ref":"Hosea 14:3","synthesized":"Assyria will not save us, nor will we ride on horses. We will never again say, ‘Our gods!’ to the work of our own hands.   For in You the fatherless find compassion.”","sources":{"KJV":{"text":"Asshur shall not save us; we will not ride upon horses: neither will we say any more to the work of our hands, Ye are our gods: for in thee the fatherless findeth mercy."},"BSB":{"text":"Assyria will not save us, nor will we ride on horses. We will never again say, ‘Our gods!’ to the work of our own hands.   For in You the fatherless find compassion.”"}},"definableWords":["work"],"peopleInVerse":[]},"4":{"text":"I will heal their backsliding, I will love them freely: for mine anger is turned away from him.","ref":"Hosea 14:4","synthesized":"I will heal their apostasy; I will freely love them, for My anger has turned away from them.","sources":{"KJV":{"text":"I will heal their backsliding, I will love them freely: for mine anger is turned away from him."},"BSB":{"text":"I will heal their apostasy; I will freely love them, for My anger has turned away from them."}},"definableWords":["heal","love","anger"],"peopleInVerse":[]},"5":{"text":"I will be as the dew unto Israel: he shall grow as the lily, and cast forth his roots as Lebanon.","ref":"Hosea 14:5","synthesized":"I will be like the dew to Israel; he will blossom like the lily and take root like the cedars of Lebanon.","sources":{"KJV":{"text":"I will be as the dew unto Israel: he shall grow as the lily, and cast forth his roots as Lebanon."},"BSB":{"text":"I will be like the dew to Israel; he will blossom like the lily and take root like the cedars of Lebanon."}},"definableWords":["Israel"],"peopleInVerse":[]},"6":{"text":"His branches shall spread, and his beauty shall be as the olive tree, and his smell as Lebanon.","ref":"Hosea 14:6","synthesized":"His shoots will sprout, and his splendor will be like the olive tree, his fragrance like the cedars of Lebanon.","sources":{"KJV":{"text":"His branches shall spread, and his beauty shall be as the olive tree, and his smell as Lebanon."},"BSB":{"text":"His shoots will sprout, and his splendor will be like the olive tree, his fragrance like the cedars of Lebanon."}},"definableWords":["tree"],"peopleInVerse":[]},"7":{"text":"They that dwell under his shadow shall return; they shall revive as the corn, and grow as the vine: the scent thereof shall be as the wine of Lebanon.","ref":"Hosea 14:7","synthesized":"They will return and dwell in his shade; they will grow grain and blossom like the vine. His renown will be like the wine of Lebanon.","sources":{"KJV":{"text":"They that dwell under his shadow shall return; they shall revive as the corn, and grow as the vine: the scent thereof shall be as the wine of Lebanon."},"BSB":{"text":"They will return and dwell in his shade; they will grow grain and blossom like the vine. His renown will be like the wine of Lebanon."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Ephraim shall say, What have I to do any more with idols? I have heard him, and observed him: I am like a green fir tree. From me is thy fruit found.","ref":"Hosea 14:8","synthesized":"O Ephraim, what have I to do anymore with idols? It is I who answer and watch over him. I am like a flourishing cypress; your fruit comes from Me.","sources":{"KJV":{"text":"Ephraim shall say, What have I to do any more with idols? I have heard him, and observed him: I am like a green fir tree. From me is thy fruit found."},"BSB":{"text":"O Ephraim, what have I to do anymore with idols? It is I who answer and watch over him. I am like a flourishing cypress; your fruit comes from Me."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Who is wise, and he shall understand these things? prudent, and he shall know them? for the ways of the LORD are right, and the just shall walk in them: but the transgressors shall fall therein.","ref":"Hosea 14:9","synthesized":"Whoever is wise, let him understand these things; whoever is discerning, let him know them. For the ways of the LORD are right, and the righteous walk in them but the rebellious stumble in them.","sources":{"KJV":{"text":"Who is wise, and he shall understand these things? prudent, and he shall know them? for the ways of the LORD are right, and the just shall walk in them: but the transgressors shall fall therein."},"BSB":{"text":"Whoever is wise, let him understand these things; whoever is discerning, let him know them. For the ways of the LORD are right, and the righteous walk in them but the rebellious stumble in them."}},"definableWords":["LORD","righteous","walk"],"peopleInVerse":[]}}}};